'use client';

import { useLocale, useTranslations } from 'next-intl';
import { Link } from '@/i18n/navigation';
import { PublicPageShell } from '@/components/public-page-shell';
import {
  Shield,
  Zap,
  Terminal,
  CheckCircle,
  ArrowRight,
  Key,
  Smartphone,
  AlertTriangle,
  Lock,
  ShoppingCart,
} from 'lucide-react';
import { getApiPublicContent, type ApiSecurityRule } from '@/lib/i18n/pages/api-public-content';

const USE_CASE_ICONS = {
  shoppingCart: ShoppingCart,
  zap: Zap,
  smartphone: Smartphone,
} as const;

const SECURITY_ICONS = {
  lock: Lock,
  shield: Shield,
  alertTriangle: AlertTriangle,
  checkCircle: CheckCircle,
} as const;

function SecurityRuleRow({ rule }: { rule: ApiSecurityRule }) {
  const Icon = SECURITY_ICONS[rule.iconKey];
  return (
    <div className="flex items-start gap-3 rounded-xl border border-white/10 bg-white/5 px-4 py-3">
      <Icon className="w-4 h-4 text-amber-400 mt-0.5 shrink-0" />
      <p className="text-sm text-gray-400 leading-relaxed">{rule.text}</p>
    </div>
  );
}

export default function ApiPage() {
  const locale = useLocale();
  const t = useTranslations('PublicPages');
  const c = getApiPublicContent(locale);
  const honestBodyHtml = c.honestBodyHtml.replace(
    'href="/dashboard"',
    `href="/${locale}/dashboard"`
  );

  return (
    <PublicPageShell title={t('api.title')} subtitle={t('api.subtitle')}>
      <div className="mb-12 rounded-2xl border border-amber-500/20 bg-amber-500/5 p-6">
        <div className="flex items-start gap-3">
          <AlertTriangle className="w-5 h-5 text-amber-400 shrink-0 mt-0.5" />
          <div>
            <p className="font-semibold text-white mb-1 text-sm">{c.honestTitle}</p>
            <p
              className="text-sm text-gray-400 leading-relaxed [&_strong]:text-white [&_em]:text-gray-300"
              dangerouslySetInnerHTML={{ __html: honestBodyHtml }}
            />
          </div>
        </div>
      </div>

      <section className="mb-12">
        <h2 className="font-display text-xl font-bold text-white mb-6">{c.sectionUseCases}</h2>
        <div className="grid gap-4 sm:grid-cols-3">
          {c.useCases.map((uc) => {
            const Icon = USE_CASE_ICONS[uc.iconKey];
            return (
              <div key={uc.title} className="rounded-2xl border border-white/10 bg-white/5 p-6">
                <div className="flex items-center justify-between mb-4">
                  <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-[#2563eb]/20">
                    <Icon className="w-5 h-5 text-[#2563eb]" />
                  </div>
                  <span className={`rounded-full px-2.5 py-0.5 text-xs font-bold ${uc.badgeColor}`}>{uc.badge}</span>
                </div>
                <h3 className="font-display font-semibold text-white mb-2 text-sm">{uc.title}</h3>
                <p className="text-xs text-gray-400 leading-relaxed">{uc.description}</p>
              </div>
            );
          })}
        </div>
      </section>

      <section className="mb-12">
        <h2 className="font-display text-xl font-bold text-white mb-4 flex items-center gap-2">
          <Key className="w-5 h-5 text-[#2563eb]" />
          {c.sectionKeyTitle}
        </h2>
        <div className="rounded-2xl border border-white/10 bg-white/5 p-5">
          <p
            className="text-sm text-gray-400 leading-relaxed mb-4 [&_code]:text-gray-300 [&_code]:font-mono [&_code]:text-xs [&_code]:bg-white/10 [&_code]:px-1.5 [&_code]:py-0.5 [&_code]:rounded"
            dangerouslySetInnerHTML={{ __html: c.keyIntro }}
          />
          <div className="grid gap-3 sm:grid-cols-3">
            {c.keySteps.map(({ step, label }) => (
              <div key={step} className="flex items-center gap-3 rounded-xl border border-white/10 bg-white/5 px-4 py-3">
                <span className="flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-[#2563eb]/20 text-xs font-bold text-[#2563eb]">
                  {step}
                </span>
                <span className="text-sm text-gray-400">{label}</span>
              </div>
            ))}
          </div>
          <p className="text-xs text-gray-600 mt-3">{c.keyFootnote}</p>
        </div>
      </section>

      <section className="mb-12">
        <h2 className="font-display text-xl font-bold text-white mb-4 flex items-center gap-2">
          <Terminal className="w-5 h-5 text-[#2563eb]" />
          {c.sectionEndpoint}
        </h2>
        <div className="rounded-2xl border border-white/10 bg-slate-900/70 overflow-hidden">
          <div className="flex items-center gap-2.5 px-4 py-3 border-b border-white/10 bg-white/5">
            <span className="rounded bg-blue-500/20 text-blue-400 px-2 py-0.5 text-xs font-bold">POST</span>
            <code className="text-xs text-gray-300 font-mono">{t('api.webhookPath')}</code>
          </div>
          <pre className="p-5 text-xs text-gray-300 font-mono overflow-x-auto leading-relaxed whitespace-pre-wrap">
            {c.endpointDoc}
          </pre>
        </div>
      </section>

      <section className="mb-12">
        <h2 className="font-display text-xl font-bold text-white mb-4 flex items-center gap-2">
          <Shield className="w-5 h-5 text-[#2563eb]" />
          {c.sectionSecurity}
        </h2>
        <div className="space-y-3">
          {c.securityRules.map((rule) => (
            <SecurityRuleRow key={rule.text} rule={rule} />
          ))}
        </div>
      </section>

      <section className="mb-12">
        <h2 className="font-display text-xl font-bold text-white mb-4 flex items-center gap-2">
          <AlertTriangle className="w-5 h-5 text-[#2563eb]" />
          {c.sectionCodes}
        </h2>
        <div className="rounded-2xl border border-white/10 bg-white/5 overflow-hidden">
          {c.errorCodes.map(({ code, desc }, i) => (
            <div
              key={code}
              className={`flex items-center gap-4 px-5 py-3.5 ${i < c.errorCodes.length - 1 ? 'border-b border-white/5' : ''} hover:bg-white/5 transition-colors`}
            >
              <span
                className={`font-mono font-bold text-sm w-10 shrink-0 ${code === '200' ? 'text-emerald-400' : Number(code) >= 500 ? 'text-red-400' : 'text-amber-400'}`}
              >
                {code}
              </span>
              <span className="text-sm text-gray-400">{desc}</span>
            </div>
          ))}
        </div>
      </section>

      <section className="mb-12">
        <h2 className="font-display text-xl font-bold text-white mb-4">{c.zapierSectionTitle}</h2>
        <div className="rounded-2xl border border-white/10 bg-slate-900/70 overflow-hidden">
          <div className="flex items-center gap-2.5 px-4 py-3 border-b border-white/10 bg-white/5">
            <Zap className="w-4 h-4 text-amber-400" />
            <span className="text-xs font-semibold text-gray-300">{c.zapierPanelLabel}</span>
          </div>
          <pre className="p-5 text-xs text-gray-300 font-mono leading-relaxed whitespace-pre-wrap">{c.zapierExample}</pre>
        </div>
      </section>

      <div className="rounded-2xl border border-[#2563eb]/30 bg-[#2563eb]/10 p-7 text-center">
        <h3 className="font-display text-xl font-bold text-white mb-2">{c.ctaTitle}</h3>
        <p className="text-sm text-gray-400 mb-6 max-w-lg mx-auto">{c.ctaBody}</p>
        <div className="flex flex-col sm:flex-row gap-3 justify-center">
          <Link
            href="/signup?mode=trial"
            className="inline-flex items-center justify-center gap-2 px-6 py-3 rounded-xl bg-[#2563eb] text-white font-semibold hover:bg-[#1d4ed8] transition-colors"
          >
            {c.ctaTrial}
            <ArrowRight className="w-4 h-4" />
          </Link>
          <Link
            href="/documentation"
            className="inline-flex items-center justify-center gap-2 px-6 py-3 rounded-xl border border-white/20 text-white font-medium hover:bg-white/5 transition-colors"
          >
            {c.ctaDoc}
          </Link>
        </div>
      </div>
    </PublicPageShell>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { useLocale } from 'next-intl';
import { createClient } from '@/lib/supabase/client';
import { parseAuthParamsFromHref, stripAuthParamsFromBrowserUrl } from '@/lib/auth/auth-callback-url';
import { withLocalePrefix } from '@/lib/i18n/with-locale-prefix';
import { useTranslations } from 'next-intl';
import { Logo } from '@/components/logo';
import { isAuthPKCECodeVerifierMissingError, type EmailOtpType } from '@supabase/auth-js';

/**
 * OAuth / magic link (generateLink + e-mail tiers) / fragments implicites.
 * Les liens admin.generateLink ne fournissent pas de code_verifier PKCE : il faut accepter
 * les tokens en hash ou échanger le code avec un client flowType implicit puis copier la session.
 */
export default function AuthCallbackPage() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const locale = useLocale();
  const t = useTranslations('Common.authCallback');
  const [, setRedirecting] = useState(false);
  const [showDelayedUi, setShowDelayedUi] = useState(false);

  useEffect(() => {
    const id = window.setTimeout(() => setShowDelayedUi(true), 1000);
    return () => window.clearTimeout(id);
  }, []);

  useEffect(() => {
    async function redirectToTarget(session: { user?: { id: string } } | null) {
      if (!session) return;
      const nextRaw = searchParams?.get('next');
      const next = nextRaw ? decodeURIComponent(nextRaw) : '';
      const isLegacyRecovery =
        typeof window !== 'undefined' && window.location.hash?.includes('type=recovery');

      const target = isLegacyRecovery
        ? `/${locale}/login?message=passwordless-recovery`
        : withLocalePrefix(locale, next, '/dashboard');

      if (!isLegacyRecovery) {
        await fetch('/api/auth/sync-oauth-profile', { method: 'POST' }).catch(() => {});
      }
      router.replace(target);
    }

    async function exchangeCodeWithoutPkceVerifier(code: string) {
      const url = process.env.NEXT_PUBLIC_SUPABASE_URL;
      const key = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;
      if (!url || !key) return null;
      const { createClient: createRaw } = await import('@supabase/supabase-js');
      const implicit = createRaw(url, key, {
        auth: {
          flowType: 'implicit',
          persistSession: false,
          autoRefreshToken: false,
          detectSessionInUrl: false,
          storage: {
            getItem: () => null,
            setItem: () => {},
            removeItem: () => {},
          },
        },
      });
      const { data, error } = await implicit.auth.exchangeCodeForSession(code);
      if (error || !data?.session) return null;
      return data.session;
    }

    async function handleCallback() {
      if (typeof window === 'undefined') return;

      const supabase = createClient();
      await supabase.auth.getSession();

      const href = window.location.href;
      const params = parseAuthParamsFromHref(href);

      if (params.error || params.error_description) {
        setRedirecting(true);
        const msg = params.error_description || params.error || 'auth_failed';
        router.replace(
          `/${locale}/login?error=auth-callback-failed&detail=${encodeURIComponent(msg.slice(0, 200))}`
        );
        return;
      }

      const accessToken = params.access_token;
      const refreshToken = params.refresh_token;
      if (accessToken && refreshToken) {
        const { data, error } = await supabase.auth.setSession({
          access_token: accessToken,
          refresh_token: refreshToken,
        });
        if (!error && data.session) {
          stripAuthParamsFromBrowserUrl();
          setRedirecting(true);
          await redirectToTarget(data.session);
          return;
        }
      }

      const tokenHash = params.token_hash;
      const rawType = params.type;
      if (tokenHash && rawType) {
        const allowed: EmailOtpType[] = [
          'magiclink',
          'email',
          'signup',
          'recovery',
          'email_change',
          'invite',
        ];
        const otpType = (allowed.includes(rawType as EmailOtpType) ? rawType : 'email') as EmailOtpType;
        const { data, error } = await supabase.auth.verifyOtp({
          token_hash: tokenHash,
          type: otpType,
        });
        if (!error && data.session) {
          stripAuthParamsFromBrowserUrl();
          setRedirecting(true);
          await redirectToTarget(data.session);
          return;
        }
      }

      const { data: { session: existingSession } } = await supabase.auth.getSession();
      if (existingSession) {
        stripAuthParamsFromBrowserUrl();
        setRedirecting(true);
        await redirectToTarget(existingSession);
        return;
      }

      const code = searchParams?.get('code') ?? params.code;
      if (code) {
        try {
          const { data, error: exchangeError } = await supabase.auth.exchangeCodeForSession(code);
          if (!exchangeError && data?.session) {
            stripAuthParamsFromBrowserUrl();
            setRedirecting(true);
            await redirectToTarget(data.session);
            return;
          }

          const retryAfterError =
            exchangeError &&
            (isAuthPKCECodeVerifierMissingError(exchangeError) ||
              (exchangeError.message ?? '').toLowerCase().includes('code verifier'));

          if (retryAfterError) {
            const fallbackSession = await exchangeCodeWithoutPkceVerifier(code);
            if (fallbackSession) {
              const { error: setErr } = await supabase.auth.setSession({
                access_token: fallbackSession.access_token,
                refresh_token: fallbackSession.refresh_token,
              });
              if (!setErr) {
                stripAuthParamsFromBrowserUrl();
                setRedirecting(true);
                await redirectToTarget(fallbackSession);
                return;
              }
            }
          }

          const { data: { session: sessionAfterError } } = await supabase.auth.getSession();
          if (sessionAfterError) {
            stripAuthParamsFromBrowserUrl();
            setRedirecting(true);
            await redirectToTarget(sessionAfterError);
            return;
          }
        } catch (err) {
          const { data: { session } } = await supabase.auth.getSession();
          if (session) {
            stripAuthParamsFromBrowserUrl();
            setRedirecting(true);
            await redirectToTarget(session);
            return;
          }
          console.error('[auth/callback] Exception exchangeCodeForSession:', err);
        }
      } else {
        const hash = window.location.hash;
        const hasHashTokens = hash.includes('access_token') || hash.includes('refresh_token');
        if (hasHashTokens) {
          const { data: { session } } = await supabase.auth.getSession();
          if (session) {
            stripAuthParamsFromBrowserUrl();
            setRedirecting(true);
            await redirectToTarget(session);
            return;
          }
        }
      }

      const { data: { session: finalSession } } = await supabase.auth.getSession();
      if (finalSession) {
        stripAuthParamsFromBrowserUrl();
        setRedirecting(true);
        await redirectToTarget(finalSession);
        return;
      }

      setRedirecting(true);
      router.replace(`/${locale}/login?error=auth-callback-failed`);
    }

    void handleCallback();
  }, [router, locale, searchParams]);

  return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 text-slate-800 [color-scheme:light]">
      {showDelayedUi ? (
        <>
          <div className="animate-spin shadow-sm" style={{ animationDuration: '1.25s' }} aria-hidden>
            <Logo size="lg" priority />
          </div>
          <p className="text-slate-600 text-sm mt-6">{t('redirecting')}</p>
        </>
      ) : null}
    </div>
  );
}

'use client';

import { useState, Suspense } from 'react';
import type { ReactNode } from 'react';
import { useSearchParams } from 'next/navigation';
import { useTranslations } from 'next-intl';
import { Link } from '@/i18n/navigation';
import { Logo } from '@/components/logo';
import { Loader2 } from 'lucide-react';
import { toast } from 'sonner';

function BananoPinResetForm() {
  const t = useTranslations('BananoPinReset');
  const searchParams = useSearchParams();
  const token = searchParams.get('token')?.trim() ?? '';

  const [pinA, setPinA] = useState('');
  const [pinB, setPinB] = useState('');
  const [busy, setBusy] = useState(false);

  async function onSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (pinA.length < 4 || pinA !== pinB) {
      toast.error(t('toastPinMismatch'));
      return;
    }
    setBusy(true);
    try {
      const res = await fetch('/api/banano/pin/reset-complete', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ token, pin: pinA }),
      });
      const data = await res.json().catch(() => ({}));
      if (!res.ok) {
        throw new Error(typeof data.error === 'string' ? data.error : t('errResetFailed'));
      }
      toast.success(t('toastSuccess'));
      setPinA('');
      setPinB('');
    } catch (err) {
      toast.error(err instanceof Error ? err.message : t('errGeneric'));
    } finally {
      setBusy(false);
    }
  }

  if (!token) {
    return (
      <div className="min-h-[70vh] flex flex-col items-center justify-center px-4 py-12">
        <div className="mb-8">
          <Logo size="lg" />
        </div>
        <div className="max-w-md w-full rounded-2xl border border-slate-200 dark:border-zinc-700 bg-white dark:bg-zinc-900 p-8 shadow-sm text-center">
          <h1 className="text-lg font-semibold text-slate-900 dark:text-zinc-100 mb-2">
            {t('titleInvalidLink')}
          </h1>
          <p className="text-sm text-slate-600 dark:text-zinc-400 mb-6 leading-relaxed">
            {t('bodyInvalidLink')}
          </p>
          <Link
            href="/login"
            className="inline-flex items-center justify-center rounded-xl bg-[#2563eb] text-white font-semibold text-sm px-5 py-2.5 hover:brightness-110"
          >
            {t('linkLogin')}
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-[70vh] flex flex-col items-center justify-center px-4 py-12">
      <div className="mb-8">
        <Logo size="lg" />
      </div>
      <div className="max-w-md w-full rounded-2xl border border-slate-200 dark:border-zinc-700 bg-white dark:bg-zinc-900 p-8 shadow-sm">
        <h1 className="text-lg font-semibold text-slate-900 dark:text-zinc-100 mb-1">
          {t('titleNewPin')}
        </h1>
        <p className="text-sm text-slate-600 dark:text-zinc-400 mb-6 leading-relaxed">
          {t.rich('bodyNewPinRich', {
            strong: (chunks: ReactNode) => <strong>{chunks}</strong>,
          })}
        </p>
        <form onSubmit={onSubmit} className="space-y-4">
          <div>
            <label htmlFor="banano-reset-pin-a" className="block text-sm font-medium text-slate-700 dark:text-zinc-300 mb-1.5">
              {t('labelNewCode')}
            </label>
            <input
              id="banano-reset-pin-a"
              type="password"
              inputMode="numeric"
              autoComplete="new-password"
              pattern="\d*"
              maxLength={8}
              value={pinA}
              onChange={(e) => setPinA(e.target.value.replace(/\D/g, '').slice(0, 8))}
              className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-zinc-700 bg-white dark:bg-zinc-800/50 text-slate-900 dark:text-zinc-100 tracking-widest font-mono focus:outline-none focus:ring-2 focus:ring-[#2563eb]/30"
              placeholder="••••"
              required
            />
          </div>
          <div>
            <label htmlFor="banano-reset-pin-b" className="block text-sm font-medium text-slate-700 dark:text-zinc-300 mb-1.5">
              {t('labelConfirm')}
            </label>
            <input
              id="banano-reset-pin-b"
              type="password"
              inputMode="numeric"
              autoComplete="new-password"
              pattern="\d*"
              maxLength={8}
              value={pinB}
              onChange={(e) => setPinB(e.target.value.replace(/\D/g, '').slice(0, 8))}
              className="w-full px-4 py-2.5 rounded-xl border border-slate-200 dark:border-zinc-700 bg-white dark:bg-zinc-800/50 text-slate-900 dark:text-zinc-100 tracking-widest font-mono focus:outline-none focus:ring-2 focus:ring-[#2563eb]/30"
              placeholder="••••"
              required
            />
          </div>
          <button
            type="submit"
            disabled={busy || pinA.length < 4 || pinA !== pinB}
            className="w-full py-3 rounded-xl font-semibold text-white bg-[#2563eb] hover:brightness-110 disabled:opacity-50 flex items-center justify-center gap-2"
          >
            {busy ? <Loader2 className="w-4 h-4 animate-spin" /> : null}
            {t('btnSubmit')}
          </button>
        </form>
        <p className="mt-6 text-xs text-slate-500 dark:text-zinc-500 text-center">
          <Link href="/dashboard/settings" className="text-[#2563eb] hover:underline">
            {t('linkBackSettings')}
          </Link>
        </p>
      </div>
    </div>
  );
}

export default function BananoPinResetPage() {
  return (
    <Suspense
      fallback={
        <div className="min-h-[50vh] flex items-center justify-center">
          <Loader2 className="w-8 h-8 animate-spin text-slate-400" />
        </div>
      }
    >
      <BananoPinResetForm />
    </Suspense>
  );
}

import { notFound } from 'next/navigation';
import { getTranslations, setRequestLocale } from 'next-intl/server';
import { Link } from '@/i18n/navigation';
import { PublicPageShell } from '@/components/public-page-shell';
import {
  ArrowLeft, Calendar, Clock, Tag, TrendingUp,
  AlertTriangle, CheckCircle, ArrowRight, ExternalLink, BookOpen,
} from 'lucide-react';
import type { Section } from '@/lib/i18n/blog-articles';
import { getBlogArticles } from '@/lib/i18n/blog-articles';
import { BLOG_ARTICLES_FR } from '@/lib/i18n/blog-articles/fr';

/* ─────────────────────────────────────────────────────────────────────────────
   ARTICLES DATABASE (locale-specific bodies in lib/i18n/blog-articles)
───────────────────────────────────────────────────────────────────────────── */

/* ─────────────────────────────────────────────────────────────────────────────
   RENDERERS
───────────────────────────────────────────────────────────────────────────── */
const CATEGORY_COLORS_BY_KEY: Record<string, string> = {
  product: 'bg-blue-500/20 text-blue-400',
  trends: 'bg-violet-500/20 text-violet-400',
  regulation: 'bg-amber-500/20 text-amber-400',
  guide: 'bg-emerald-500/20 text-emerald-400',
  useCase: 'bg-cyan-500/20 text-cyan-400',
  seoLocal: 'bg-orange-500/20 text-orange-400',
  cybersecurity: 'bg-red-500/20 text-red-400',
  studies: 'bg-pink-500/20 text-pink-400',
  international: 'bg-teal-500/20 text-teal-400',
};

/** Libellés de catégorie dans les corps FR/EN → clé i18n (badge + traduction) */
const LEGACY_FR_CATEGORY_TO_KEY: Record<string, string> = {
  Produit: 'product',
  Tendances: 'trends',
  Réglementation: 'regulation',
  'Guide pratique': 'guide',
  "Cas d'usage": 'useCase',
  'SEO Local': 'seoLocal',
  Cybersécurité: 'cybersecurity',
  Études: 'studies',
  International: 'international',
};
const LEGACY_EN_CATEGORY_TO_KEY: Record<string, string> = {
  Product: 'product',
  Trends: 'trends',
  Regulation: 'regulation',
  'Practical guide': 'guide',
  'Use case': 'useCase',
  'Local SEO': 'seoLocal',
  Cybersecurity: 'cybersecurity',
  Studies: 'studies',
  International: 'international',
};
function resolveCategoryKey(label: string) {
  return (
    LEGACY_FR_CATEGORY_TO_KEY[label] ??
    LEGACY_EN_CATEGORY_TO_KEY[label] ??
    'product'
  );
}

function Callout({ type, text, label }: { type: string; text: string; label?: string }) {
