const DASHBOARD_HEADER_DATE_OPTIONS: Pick<
  Intl.DateTimeFormatOptions,
  'weekday' | 'day' | 'month' | 'year'
> = {
  weekday: 'long',
  day: 'numeric',
  month: 'long',
  year: 'numeric',
};

type Props = {
  params: Promise<{ locale: string }>;
  searchParams: Promise<{ welcome?: string; status?: string; plan?: string; q?: string; from?: string; to?: string; period?: string }>;
};

export const dynamic = 'force-dynamic';

export async function generateMetadata({
  params,
}: {
  params: Promise<{ locale: string }>;
}): Promise<Metadata> {
  const { locale } = await params;
  const t = await getTranslations({ locale, namespace: 'Dashboard.layout' });
  return {
    title: t('title'),
    alternates: {
      canonical: `${REPUTEXA_SITE_URL}/${locale}/dashboard`,
    },
  };
}

type ReviewDisplay = {
  id: string;
  reviewerName: string;
  rating: number;
  comment: string;
  source: string;
  responseText?: string | null;
  createdAt: string;
};

export default async function DashboardPage({ params, searchParams }: Props) {
  const { locale } = await params;
  const { q, from, to, period } = await searchParams;
  setRequestLocale(locale);

  const t = await getTranslations('Dashboard.overview');
  const tShell = await getTranslations('Dashboard.shell');
  const supabase = await createClient();
  const { data: { user: supabaseUser } } = await supabase.auth.getUser();

  let reviews: ReviewDisplay[] = [];
  let totalReviews = 0;
  let avgRating = 0;
  let securityAlerts = 0;
  let establishmentName = '';

  const today = startOfDay(new Date());
  const defaultFrom = startOfDay(subMonths(today, 1));

  let fromDate: Date | null = null;
  let toDate: Date | null = null;

  if (from && to) {
    const parsedFrom = new Date(from);
    const parsedTo = new Date(to);
    if (!Number.isNaN(parsedFrom.getTime()) && !Number.isNaN(parsedTo.getTime())) {
      fromDate = startOfDay(parsedFrom);
      toDate = endOfDay(parsedTo);
    }
  }

  if (!fromDate || !toDate) {
    if (period === '7d') {
      fromDate = startOfDay(subDays(today, 6));
      toDate = endOfDay(today);
    } else if (period === '30d') {
      fromDate = startOfDay(subDays(today, 29));
      toDate = endOfDay(today);
    } else if (period === '3m') {
      fromDate = startOfDay(subMonths(today, 3));
      toDate = endOfDay(today);
    } else if (period === '12m') {
      fromDate = startOfDay(subMonths(today, 12));
      toDate = endOfDay(today);
    } else {
      fromDate = defaultFrom;
      toDate = endOfDay(today);
    }
  }

  const currentFromIso = fromDate.toISOString();
  const currentToIso = toDate.toISOString();

  const diffMs = toDate.getTime() - fromDate.getTime();
  const prevTo = new Date(fromDate.getTime() - 1);
  const prevFrom = new Date(prevTo.getTime() - diffMs);
  const prevFromIso = prevFrom.toISOString();
  const prevToIso = prevTo.toISOString();

  let prevTotalReviews = 0;
  let prevAvgRating = 0;
  let prevPositiveCount = 0;
  let prevNegativeCount = 0;
  let llmBudgetDisplay: ReturnType<typeof getEffectiveLlmBudgetDisplay> | null = null;
  let displayTimeZone = resolveMerchantTimeZone(null);

  if (supabaseUser) {
    const { data: profile } = await supabase
      .from('profiles')
      .select('establishment_name, timezone')
      .eq('id', supabaseUser.id)
      .single();
    if (profile?.establishment_name) establishmentName = profile.establishment_name;
    displayTimeZone = resolveMerchantTimeZone((profile?.timezone as string | null) ?? null);

    const { data: budgetRow } = await supabase
      .from('ai_llm_usage_budget')
      .select('period_start, call_count, daily_soft_limit, daily_hard_limit')
      .eq('user_id', supabaseUser.id)
      .maybeSingle();
    llmBudgetDisplay = getEffectiveLlmBudgetDisplay(budgetRow);

    const rawLoc = (await cookies()).get('reputexa_active_location')?.value;
    const activeLocationId =
      rawLoc && rawLoc.trim() !== '' ? rawLoc.trim() : 'profile';

    if (activeLocationId !== 'profile' && /^[0-9a-f-]{36}$/i.test(activeLocationId)) {
      const { data: estRow } = await supabase
        .from('establishments')
        .select('name')
        .eq('id', activeLocationId)
        .eq('user_id', supabaseUser.id)
        .maybeSingle();
      if (estRow?.name && String(estRow.name).trim()) {
        establishmentName = String(estRow.name).trim();
      }
    }

    let reviewsQuery = supabase
      .from('reviews')
      .select('id, reviewer_name, rating, comment, source, response_text, created_at')
      .eq('user_id', supabaseUser.id)
      .gte('created_at', currentFromIso)
      .lte('created_at', currentToIso);
    if (activeLocationId === 'profile') {
      reviewsQuery = reviewsQuery.is('establishment_id', null);
    } else if (activeLocationId && /^[0-9a-f-]{36}$/i.test(activeLocationId)) {
      reviewsQuery = reviewsQuery.eq('establishment_id', activeLocationId);
    }
    const { data: supabaseReviews } = await reviewsQuery.order('created_at', { ascending: false });
    reviews = (supabaseReviews ?? []).map((r) => {
      const safeRating = typeof r.rating === 'number' && Number.isFinite(r.rating) ? r.rating : 0;
      const created =
        typeof r.created_at === 'string' && r.created_at
          ? r.created_at
          : new Date().toISOString();
      return {
        id: String(r.id),
        reviewerName: String(r.reviewer_name ?? 'Client'),
        rating: safeRating,
        comment: String(r.comment ?? ''),
        source: String(r.source ?? 'Unknown'),
        responseText: r.response_text ?? null,
        createdAt: created,
      };
    });
    totalReviews = reviews.length;
    avgRating = reviews.length ? reviews.reduce((s, r) => s + r.rating, 0) / reviews.length : 0;
    securityAlerts = reviews.filter((r) => r.rating < 3).length;

    let prevReviewsQuery = supabase
      .from('reviews')
      .select('id, rating, created_at')
      .eq('user_id', supabaseUser.id)
      .gte('created_at', prevFromIso)
      .lte('created_at', prevToIso);
    if (activeLocationId === 'profile') {
      prevReviewsQuery = prevReviewsQuery.is('establishment_id', null);
    } else if (activeLocationId && /^[0-9a-f-]{36}$/i.test(activeLocationId)) {
      prevReviewsQuery = prevReviewsQuery.eq('establishment_id', activeLocationId);
    }
    const { data: prevReviewsRaw } = await prevReviewsQuery;

    const prevReviews = (prevReviewsRaw ?? []).map((r) => {
      const safeRating =
        typeof r.rating === 'number' && Number.isFinite(r.rating) ? r.rating : 0;
      return { rating: safeRating, createdAt: String(r.created_at ?? '') };
    });

    prevTotalReviews = prevReviews.length;
    prevAvgRating = prevReviews.length
      ? prevReviews.reduce((s, r) => s + r.rating, 0) / prevReviews.length
      : 0;
    prevPositiveCount = prevReviews.filter((r) => r.rating >= 4).length;
    prevNegativeCount = prevReviews.filter((r) => r.rating <= 3).length;
  } else {
    const [prismaReviews, prevPrismaReviews] = await Promise.all([
      prisma.review.findMany({
        where: { createdAt: { gte: fromDate, lte: toDate } },
        orderBy: { createdAt: 'desc' },
      }),
      prisma.review.findMany({
        where: { createdAt: { gte: prevFrom, lte: prevTo } },
        orderBy: { createdAt: 'desc' },
      }),
    ]);
    reviews = prismaReviews.map((r) => {
      const safeRating = typeof r.rating === 'number' && Number.isFinite(r.rating) ? r.rating : 0;
      const created =
        r.createdAt instanceof Date && !Number.isNaN(r.createdAt.getTime())
          ? r.createdAt.toISOString()
          : new Date().toISOString();
      return {
        id: String(r.id),
        reviewerName: String(r.establishmentName ?? 'Client'),
        rating: safeRating,
        comment: String(r.reviewText ?? ''),
        source: 'Google',
        responseText: r.responseText ?? null,
        createdAt: created,
      };
    });
    totalReviews = reviews.length;
    avgRating = reviews.length ? reviews.reduce((s, r) => s + r.rating, 0) / reviews.length : 0;
    securityAlerts = reviews.filter((r) => r.rating < 3).length;

    prevTotalReviews = prevPrismaReviews.length;
    prevAvgRating = prevPrismaReviews.length
      ? prevPrismaReviews.reduce(
          (s, r) =>
            s +
            (typeof r.rating === 'number' && Number.isFinite(r.rating) ? r.rating : 0),
          0,
        ) / prevPrismaReviews.length
      : 0;
    prevPositiveCount = prevPrismaReviews.filter(
      (r) => typeof r.rating === 'number' && r.rating >= 4,
    ).length;
    prevNegativeCount = prevPrismaReviews.filter(
      (r) => typeof r.rating === 'number' && r.rating <= 3,
    ).length;
  }

  if (!establishmentName.trim()) {
    establishmentName = tShell('defaultEstablishment');
  }

  const positiveCount = reviews.filter((r) => r.rating >= 4).length;
  const negativeCount = reviews.filter((r) => r.rating <= 3).length;

  const computeDelta = (current: number, previous: number): number | null => {
    if (!previous || previous <= 0) return null;
    return ((current - previous) / previous) * 100;
  };

  const avgRatingDelta = computeDelta(avgRating, prevAvgRating);
  const totalReviewsDelta = computeDelta(totalReviews, prevTotalReviews);
  const positiveDelta = computeDelta(positiveCount, prevPositiveCount);
  const negativeDelta = computeDelta(negativeCount, prevNegativeCount);

  return (
    <div className="px-4 sm:px-6 md:px-8 py-6 sm:py-8 space-y-6 max-w-[1600px] mx-auto">
      {/* Titre & date */}
      <div className="min-w-0">
        <h1 className="font-display font-bold text-2xl text-slate-900 dark:text-zinc-100 text-balance break-words">
          {t('title')}
        </h1>
        <p
          className="text-sm text-slate-500 dark:text-zinc-400 mt-0.5 break-words"
          suppressHydrationWarning
        >
          {new Date().toLocaleDateString(siteLocaleToIntlDateTag(locale), {
            ...DASHBOARD_HEADER_DATE_OPTIONS,
            timeZone: displayTimeZone,
          })}{' '}
          · {establishmentName}
        </p>
      </div>

      <DashboardDateRangePicker />

      {llmBudgetDisplay ? (
        <LlmUsageBudgetGauge
          count={llmBudgetDisplay.count}
          softLimit={llmBudgetDisplay.softLimit}
          hardLimit={llmBudgetDisplay.hardLimit}
        />
      ) : null}

      {/* Contenu principal (stats + avis) */}
      {/* Bandeau alerte IA — masqué si 0 avis */}
      {totalReviews > 0 && securityAlerts > 0 && (
      <div className="flex flex-col gap-3 rounded-2xl border border-sky-100 dark:border-zinc-800/50 bg-sky-50 dark:bg-sky-950/40 px-4 py-3 sm:flex-row sm:items-center">
        <div className="flex items-start gap-3 min-w-0 flex-1">
          <div className="flex h-8 w-8 shrink-0 items-center justify-center rounded-lg bg-sky-100 dark:bg-sky-500/20 text-sky-600 dark:text-sky-400">
            <Info className="h-4 w-4" />
          </div>
          <div className="min-w-0 flex-1">
            <p className="text-sm font-medium text-slate-900 dark:text-zinc-100 break-words">
              {t('aiAlertLead')}{' '}
              <span className="text-sky-600 font-semibold">
                {t('aiAlertNegativeReviews', { count: securityAlerts })}
              </span>{' '}
              {t('aiAlertOnPeriod')}
            </p>
            <p className="text-xs text-slate-500 dark:text-zinc-400 mt-0.5 break-words">
              {t('aiAlertSubtext')}
            </p>
          </div>
        </div>
        <Link
          href="/dashboard/responses"
          className="text-xs font-semibold text-sky-600 hover:text-sky-700 shrink-0 self-start sm:self-center text-left break-words sm:max-w-[11rem]"
        >
          {t('aiAlertCta')}
        </Link>
      </div>
      )}

      {/* Cartes de statistiques: 1 col mobile, 2 tablette, 3 desktop */}
      <section className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {/* Note moyenne (carte gradient) */}
        <StatsCard className="relative overflow-hidden rounded-2xl bg-gradient-to-br from-sky-500 to-indigo-500 text-white shadow-lg dark:shadow-glow border border-transparent dark:border-zinc-800/50 hover:shadow-[-8px_12px_24px_-10px_rgba(0,0,0,0.1),_0px_10px_15px_-3px_rgba(0,0,0,0.1)] dark:hover:shadow-none dark:hover:border-zinc-700 transition-all duration-300 ease-in-out min-w-0">
          <div className="p-4 sm:p-5 h-full flex flex-col justify-between min-w-0">
            <div className="flex items-start justify-between gap-2 mb-3 min-w-0">
              <div className="flex items-center gap-2 min-w-0 flex-1">
                <div className="w-8 h-8 rounded-xl bg-white/15 flex items-center justify-center shrink-0">
                  <StarIconSmall className="w-4 h-4 text-yellow-300" />
                </div>
                <div className="min-w-0">
                  <p className="text-xs font-medium text-white/70 break-words">
                    {t('cardAvgRating')}
                  </p>
                  <p className="text-2xl font-display font-bold leading-tight">
                    {avgRating > 0 ? avgRating.toFixed(1) : '—'}
                    <span className="text-base font-medium">/5</span>
                  </p>
                </div>
              </div>
              {avgRatingDelta != null && (
                <span className="inline-flex items-center rounded-full bg-emerald-400/15 text-emerald-100 border border-emerald-300/60 px-2 py-0.5 text-[10px] font-semibold shrink-0 max-w-[45%] text-right break-words leading-snug hyphens-auto">
                  {t('statsDeltaVsPrevious', {
                    value: `${avgRatingDelta >= 0 ? '+' : ''}${avgRatingDelta.toFixed(0)}`,
                  })}
                </span>
              )}
            </div>
            <p className="text-[11px] text-white/70 break-words">{t('avgRatingGoal')}</p>
            {avgRating > 0 && (
              <WhatsAppShareButton
                rating={avgRating.toFixed(1)}
                className="mt-2 inline-flex items-center gap-1.5 text-[10px] text-white/80 hover:text-white"
              />
            )}
          </div>
        </StatsCard>

        {/* Total avis */}
        <StatsCard className="rounded-2xl bg-white dark:bg-[#09090b] border border-slate-200 dark:border-zinc-800/50 shadow-sm dark:shadow-[4px_6px_0_rgba(0,0,0,0.5)] hover:shadow-[-8px_12px_24px_-10px_rgba(0,0,0,0.1),_0px_10px_15px_-3px_rgba(0,0,0,0.1)] dark:hover:shadow-[4px_6px_0_rgba(0,0,0,0.6)] dark:hover:border-zinc-700 p-4 sm:p-5 transition-all duration-300 ease-in-out min-w-0">
          <div className="flex items-start justify-between gap-2 mb-3 min-w-0">
            <div className="w-8 h-8 rounded-xl bg-sky-50 dark:bg-sky-500/15 flex items-center justify-center shrink-0">
              <StarIconSmall className="w-4 h-4 text-sky-600" />
            </div>
            {totalReviewsDelta != null && (
              <span className="inline-flex items-center gap-1 rounded-full bg-emerald-50 dark:bg-emerald-500/10 px-2 py-0.5 text-[10px] font-semibold text-emerald-600 shrink-0 max-w-[45%] justify-end text-right break-words leading-snug">
                {totalReviewsDelta >= 0 ? '+' : ''}
                {totalReviewsDelta.toFixed(0)}
                %
              </span>
            )}
          </div>
          <p className="text-2xl font-display font-bold text-slate-900 dark:text-zinc-100">
            {totalReviews}
          </p>
          <p className="text-xs font-medium text-slate-500 dark:text-zinc-400 break-words">
            {t('totalReviewsLabel')}
          </p>
        </StatsCard>

        {/* Avis positifs */}
        <StatsCard className="rounded-2xl bg-white dark:bg-[#09090b] border border-slate-200 dark:border-zinc-800/50 shadow-sm dark:shadow-[4px_6px_0_rgba(0,0,0,0.5)] hover:shadow-[-8px_12px_24px_-10px_rgba(0,0,0,0.1),_0px_10px_15px_-3px_rgba(0,0,0,0.1)] dark:hover:shadow-[4px_6px_0_rgba(0,0,0,0.6)] dark:hover:border-zinc-700 p-4 sm:p-5 transition-all duration-300 ease-in-out min-w-0">
          <div className="flex items-start justify-between gap-2 mb-3 min-w-0">
            <div className="w-8 h-8 rounded-xl bg-emerald-50 dark:bg-emerald-500/15 flex items-center justify-center shrink-0">
              <ThumbsUp className="w-4 h-4 text-emerald-600" />
            </div>
            {positiveDelta != null && (
              <span className="inline-flex items-center gap-1 rounded-full bg-emerald-50 dark:bg-emerald-500/10 px-2 py-0.5 text-[10px] font-semibold text-emerald-600 shrink-0 max-w-[45%] justify-end text-right break-words leading-snug">
                {positiveDelta >= 0 ? '+' : ''}
                {positiveDelta.toFixed(0)}
                %
              </span>
            )}
          </div>
          <p className="text-2xl font-display font-bold text-slate-900 dark:text-zinc-100">
            {positiveCount}
          </p>
          <p className="text-xs font-medium text-slate-500 dark:text-zinc-400 break-words">
            {t('positiveReviewsLabel')}
          </p>
          <p className="text-[11px] text-slate-400 dark:text-zinc-500 mt-1 break-words">
            {t('totalOnPeriod')}
          </p>
        </StatsCard>

        {/* Avis négatifs */}
        <StatsCard className="rounded-2xl bg-white dark:bg-[#09090b] border border-slate-200 dark:border-zinc-800/50 shadow-sm dark:shadow-[4px_6px_0_rgba(0,0,0,0.5)] hover:shadow-[-8px_12px_24px_-10px_rgba(0,0,0,0.1),_0px_10px_15px_-3px_rgba(0,0,0,0.1)] dark:hover:shadow-[4px_6px_0_rgba(0,0,0,0.6)] dark:hover:border-zinc-700 p-4 sm:p-5 transition-all duration-300 ease-in-out min-w-0">
          <div className="flex items-start justify-between gap-2 mb-3 min-w-0">
            <div className="w-8 h-8 rounded-xl bg-red-50 flex items-center justify-center shrink-0">
              <AlertTriangle className="w-4 h-4 text-red-600" />
            </div>
            {negativeDelta != null && (
              <span className="inline-flex items-center gap-1 rounded-full bg-red-50 dark:bg-red-500/10 px-2 py-0.5 text-[10px] font-semibold text-red-500 shrink-0 max-w-[45%] justify-end text-right break-words leading-snug">
                {negativeDelta >= 0 ? '+' : ''}
                {negativeDelta.toFixed(0)}
                %
              </span>
            )}
          </div>
          <p className="text-2xl font-display font-bold text-slate-900 dark:text-zinc-100">
            {negativeCount}
          </p>
          <p className="text-xs font-medium text-slate-500 dark:text-zinc-400 break-words">
            {t('negativeReviewsLabel')}
          </p>
          <p className="text-[11px] text-slate-400 dark:text-zinc-500 mt-1 break-words">
            {t('totalOnPeriod')}
          </p>
        </StatsCard>
      </section>

      {/* Graphiques: 1 col mobile, 2 tablette, 3 desktop */}
      <section className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {/* Évolution de la note */}
        <div className="lg:col-span-2 rounded-2xl bg-white dark:bg-[#09090b] border border-slate-200 dark:border-zinc-800/50 shadow-sm dark:shadow-[4px_6px_0_rgba(0,0,0,0.5)] hover:shadow-[-8px_12px_24px_-10px_rgba(0,0,0,0.1),_0px_10px_15px_-3px_rgba(0,0,0,0.1)] dark:hover:shadow-[4px_6px_0_rgba(0,0,0,0.6)] dark:hover:border-zinc-700 p-5 transition-all duration-300 ease-in-out">
          <RatingEvolutionChart reviews={reviews} locale={locale} timeZone={displayTimeZone} />
        </div>

        {/* Avis par plateforme */}
        <div className="rounded-2xl bg-white dark:bg-[#09090b] border border-slate-200 dark:border-zinc-800/50 shadow-sm dark:shadow-[4px_6px_0_rgba(0,0,0,0.5)] hover:shadow-[-8px_12px_24px_-10px_rgba(0,0,0,0.1),_0px_10px_15px_-3px_rgba(0,0,0,0.1)] dark:hover:shadow-[4px_6px_0_rgba(0,0,0,0.6)] dark:hover:border-zinc-700 p-5 transition-all duration-300 ease-in-out">
          <div className="mb-4 min-w-0">
            <h3 className="font-display font-semibold text-slate-900 dark:text-zinc-100 text-balance break-words">
              {t('platformSectionTitle')}
            </h3>
            <p className="text-xs text-slate-500 dark:text-zinc-400 mt-0.5 break-words">
              {t('distributionTotal')}
            </p>
          </div>
          <PlatformDistributionChart reviews={reviews} />
        </div>
      </section>

      {/* Derniers avis */}
      <DashboardReviewsSection
        reviews={reviews}
        useSupabaseAuth={!!supabaseUser}
        initialSearch={q ?? ''}
