type Stat = { value: string; label: string };
type CategoryFilter = { key: string; label: string };

const GUIDE_ICONS: Record<string, React.ElementType> = {
  zap: Zap,
  barChart2: BarChart2,
  messageSquare: MessageSquare,
  shield: Shield,
  bell: Bell,
  globe: Globe,
  fileText: FileText,
  bookOpen: BookOpen,
