'use client';

import { useEffect, useLayoutEffect, useMemo, useState } from 'react';
import { useLocale, useTranslations } from 'next-intl';
import { Loader2, Mail, Send, Sparkles, Wand2, Lock, Unlock, Info, CalendarClock } from 'lucide-react';
import { toast } from 'sonner';
import { broadcastFrMasterUnlockSnapshot } from '@/lib/admin/broadcast-email-shared';

const BROADCAST_DRAFT_KEY = 'reputexa_admin_broadcast_draft_v1';

type BroadcastDraftV1 = {
  v: 1;
  rawMessage: string;
  formatNote: string;
  subjectFr: string;
  htmlFr: string;
  revisionNote: string;
  /** Valeur brute `datetime-local` (fuseau du navigateur → convertie en ISO à l’envoi). */
  scheduleLocal: string;
};

export function AdminBroadcastEmailForm({ adminSecret }: { adminSecret: string }) {
  const t = useTranslations('Dashboard.adminBroadcastEmailForm');
  const locale = useLocale();
  const [rawMessage, setRawMessage] = useState('');
  const [formatNote, setFormatNote] = useState('');
  const [subjectFr, setSubjectFr] = useState('');
  const [htmlFr, setHtmlFr] = useState('');
  const [revisionNote, setRevisionNote] = useState('');
  const [scheduleLocal, setScheduleLocal] = useState('');
  const [fingerprint, setFingerprint] = useState<string | null>(null);
  const [unlockToken, setUnlockToken] = useState<string | null>(null);
  const [snapshotAtTest, setSnapshotAtTest] = useState<string | null>(null);
  const [busy, setBusy] = useState<string | null>(null);
  const [draftBootstrapped, setDraftBootstrapped] = useState(false);

  useLayoutEffect(() => {
    try {
      const raw = typeof window !== 'undefined' ? localStorage.getItem(BROADCAST_DRAFT_KEY) : null;
      if (!raw) {
        setDraftBootstrapped(true);
        return;
      }
      const p = JSON.parse(raw) as Partial<BroadcastDraftV1>;
      if (p.v !== 1) {
        setDraftBootstrapped(true);
        return;
      }
      setRawMessage(typeof p.rawMessage === 'string' ? p.rawMessage : '');
      setFormatNote(typeof p.formatNote === 'string' ? p.formatNote : '');
      setSubjectFr(typeof p.subjectFr === 'string' ? p.subjectFr : '');
      setHtmlFr(typeof p.htmlFr === 'string' ? p.htmlFr : '');
      setRevisionNote(typeof p.revisionNote === 'string' ? p.revisionNote : '');
      setScheduleLocal(typeof p.scheduleLocal === 'string' ? p.scheduleLocal : '');
      const has =
        (typeof p.rawMessage === 'string' && p.rawMessage.trim()) ||
        (typeof p.subjectFr === 'string' && p.subjectFr.trim()) ||
        (typeof p.htmlFr === 'string' && p.htmlFr.trim());
      if (has) toast.info(t('toastDraftRestored'));
    } catch {
      /* ignore */
    }
    setDraftBootstrapped(true);
    // eslint-disable-next-line react-hooks/exhaustive-deps -- one-shot draft restore; t matches mount locale
  }, []);

  useEffect(() => {
    if (!draftBootstrapped) return;
    const id = setTimeout(() => {
      try {
        const payload: BroadcastDraftV1 = {
          v: 1,
          rawMessage,
          formatNote,
          subjectFr,
          htmlFr,
          revisionNote,
          scheduleLocal,
        };
        localStorage.setItem(BROADCAST_DRAFT_KEY, JSON.stringify(payload));
      } catch {
        /* private mode / quota */
      }
    }, 450);
    return () => clearTimeout(id);
  }, [draftBootstrapped, rawMessage, formatNote, subjectFr, htmlFr, revisionNote, scheduleLocal]);

  const snapshotNow = useMemo(() => broadcastFrMasterUnlockSnapshot(subjectFr, htmlFr), [subjectFr, htmlFr]);
  const contentMatchesTest = snapshotAtTest !== null && snapshotAtTest === snapshotNow;

  const canSendAll = Boolean(
    unlockToken &&
      fingerprint &&
      subjectFr.trim() &&
      htmlFr.trim() &&
      contentMatchesTest
  );

  const clearUnlock = () => {
    setUnlockToken(null);
    setFingerprint(null);
    setSnapshotAtTest(null);
  };

  const runFormat = async () => {
    if (!rawMessage.trim()) {
      toast.error(t('toastFormatEmpty'));
      return;
    }
    setBusy('format');
    try {
      const res = await fetch('/api/admin/broadcast-email', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'x-admin-secret': adminSecret },
        body: JSON.stringify({
          action: 'format_raw',
          rawMessage: rawMessage.trim(),
          aiInstruction: formatNote.trim() || undefined,
        }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || t('toastGenericError'));
      setSubjectFr(data.subjectFr ?? '');
      setHtmlFr(data.htmlFr ?? '');
      clearUnlock();
      toast.success(t('toastFormatSuccess'));
    } catch (e) {
      toast.error(e instanceof Error ? e.message : t('toastAiError'));
    } finally {
      setBusy(null);
    }
  };

  const runRevise = async () => {
    if (!htmlFr.trim()) {
      toast.error(t('toastReviseNoHtml'));
      return;
    }
    if (!revisionNote.trim()) {
      toast.error(t('toastReviseNoNote'));
      return;
    }
    setBusy('revise');
    try {
      const res = await fetch('/api/admin/broadcast-email', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'x-admin-secret': adminSecret },
        body: JSON.stringify({
          action: 'improve',
          subjectFr: subjectFr.trim(),
          htmlFr: htmlFr.trim(),
          aiInstruction: revisionNote.trim(),
        }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || t('toastGenericError'));
      setSubjectFr(data.subjectFr ?? subjectFr);
      setHtmlFr(data.htmlFr ?? htmlFr);
      clearUnlock();
      toast.success(t('toastReviseSuccess'));
    } catch (e) {
      toast.error(e instanceof Error ? e.message : t('toastAiError'));
    } finally {
      setBusy(null);
    }
  };

  const runTest = async () => {
    if (!subjectFr.trim() || !htmlFr.trim()) {
      toast.error(t('toastSubjectBodyRequired'));
      return;
    }
    const snap = broadcastFrMasterUnlockSnapshot(subjectFr, htmlFr);
    setBusy('test');
    try {
      const res = await fetch('/api/admin/broadcast-email', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'x-admin-secret': adminSecret },
        body: JSON.stringify({
          action: 'test_send',
          subjectFr: subjectFr.trim(),
          htmlFr: htmlFr.trim(),
        }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || 'Erreur');
      setFingerprint(data.fingerprint ?? null);
      setUnlockToken(data.unlockToken ?? null);
      setSnapshotAtTest(snap);
      toast.success('E-mail envoyé — même gabarit que pour un client (exemple FR). Vérifiez votre boîte admin.');
    } catch (e) {
      toast.error(e instanceof Error ? e.message : 'Erreur');
    } finally {
      setBusy(null);
    }
  };

  const runSendAll = async () => {
    if (!unlockToken || !fingerprint) {
      toast.error(t('toastPreviewFirst'));
      return;
    }
    if (!confirm(t('confirmSendAll'))) return;
    setBusy('send_all');
    try {
      const res = await fetch('/api/admin/broadcast-email', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'x-admin-secret': adminSecret },
        body: JSON.stringify({
          action: 'send_all',
          subjectFr: subjectFr.trim(),
          htmlFr: htmlFr.trim(),
          unlockToken,
          fingerprint,
        }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || t('toastGenericError'));
      toast.success(
        t('toastSendAllResult', {
          sent: data.emailsSent ?? 0,
          failed: data.emailsFailed ?? 0,
          total: data.totalUsers ?? 0,
        })
      );
      clearUnlock();
      try {
        localStorage.removeItem(BROADCAST_DRAFT_KEY);
      } catch {
        /* ignore */
      }
      setRawMessage('');
      setFormatNote('');
      setSubjectFr('');
      setHtmlFr('');
      setRevisionNote('');
      setScheduleLocal('');
    } catch (e) {
      toast.error(e instanceof Error ? e.message : t('toastGenericError'));
    } finally {
      setBusy(null);
    }
  };

  const runSchedule = async () => {
    if (!subjectFr.trim() || !htmlFr.trim()) {
      toast.error(t('toastScheduleNeedContent'));
      return;
    }
    if (!scheduleLocal.trim()) {
      toast.error(t('toastScheduleNeedDateTime'));
      return;
    }
    const instant = new Date(scheduleLocal);
    if (Number.isNaN(instant.getTime())) {
      toast.error(t('toastScheduleBadDateTime'));
      return;
    }
    const scheduledAtIso = instant.toISOString();
    setBusy('schedule');
    try {
      const res = await fetch('/api/admin/broadcast-email', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'x-admin-secret': adminSecret },
        body: JSON.stringify({
          action: 'schedule',
          subjectFr: subjectFr.trim(),
          htmlFr: htmlFr.trim(),
          scheduled_at: scheduledAtIso,
        }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || t('toastGenericError'));
      clearUnlock();
      const when = new Date(data.scheduled_at ?? scheduledAtIso).toLocaleString(locale, {
        dateStyle: 'medium',
        timeStyle: 'short',
      });
      toast.success(t('toastScheduleSuccess', { when }));
    } catch (e) {
      toast.error(e instanceof Error ? e.message : t('toastGenericError'));
    } finally {
      setBusy(null);
    }
  };

  return (
    <div className="space-y-4">
      <div className="flex items-start gap-2 text-zinc-400 text-xs">
        <Info className="w-4 h-4 shrink-0 mt-0.5" />
        <p>
          {t.rich('introRich', {
            auto: (chunks) => <strong className="text-zinc-300">{chunks}</strong>,
            profilesCode: (chunks) => <code className="text-zinc-500">{chunks}</code>,
            adminEmail: (chunks) => <code className="text-zinc-500">{chunks}</code>,
            schedWord: (chunks) => <strong className="text-zinc-300">{chunks}</strong>,
            negation: (chunks) => <em>{chunks}</em>,
          })}
        </p>
      </div>

      <div className="rounded-xl border border-zinc-800 bg-zinc-950/40 p-4 space-y-3">
        <label className="block text-[11px] font-semibold text-zinc-500 uppercase tracking-wide">
          {t('labelFreeText')}
        </label>
        <textarea
          value={rawMessage}
          onChange={(e) => {
            setRawMessage(e.target.value);
            clearUnlock();
          }}
          rows={5}
          className="w-full bg-zinc-950 border border-zinc-700 rounded-lg px-3 py-2 text-sm text-zinc-100 placeholder:text-zinc-600"
          placeholder={t('placeholderRaw')}
        />
        <div>
          <label className="block text-[10px] text-zinc-500 mb-1">{t('labelFormatOptional')}</label>
          <input
            type="text"
            value={formatNote}
            onChange={(e) => {
              setFormatNote(e.target.value);
              clearUnlock();
            }}
            className="w-full bg-zinc-950 border border-zinc-700 rounded-lg px-3 py-2 text-sm text-zinc-300"
            placeholder={t('placeholderFormatNote')}
          />
        </div>
        <button
          type="button"
          onClick={() => void runFormat()}
          disabled={busy !== null}
          className="inline-flex items-center gap-2 rounded-lg bg-violet-600/90 hover:bg-violet-600 disabled:opacity-50 text-white text-xs font-medium px-3 py-2"
        >
          {busy === 'format' ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Sparkles className="w-3.5 h-3.5" />}
          {t('buttonFormat')}
        </button>
      </div>

      <div className="space-y-2">
        <label className="block text-[11px] text-zinc-500 uppercase tracking-wide">{t('labelSubject')}</label>
        <input
          type="text"
          value={subjectFr}
          onChange={(e) => {
            setSubjectFr(e.target.value);
            clearUnlock();
          }}
          className="w-full bg-zinc-950 border border-zinc-700 rounded-lg px-3 py-2 text-sm text-zinc-100"
          placeholder={t('placeholderSubject')}
        />
      </div>

      <div className="space-y-2">
        <label className="block text-[11px] text-zinc-500 uppercase tracking-wide">{t('labelHtml')}</label>
        <textarea
          value={htmlFr}
          onChange={(e) => {
            setHtmlFr(e.target.value);
            clearUnlock();
          }}
          rows={10}
          className="w-full bg-zinc-950 border border-zinc-700 rounded-lg px-3 py-2 text-sm text-zinc-100 font-mono placeholder:text-zinc-600"
          placeholder={t('placeholderHtml')}
        />
      </div>

      <div className="rounded-xl border border-zinc-800/80 bg-zinc-900/30 p-4 space-y-3">
        <p className="text-[11px] font-semibold text-zinc-400 uppercase tracking-wide flex items-center gap-2">
          <Wand2 className="w-3.5 h-3.5 text-violet-400" aria-hidden />
          {t('refineTitle')}
        </p>
        <textarea
          value={revisionNote}
          onChange={(e) => {
            setRevisionNote(e.target.value);
          }}
          rows={2}
          className="w-full bg-zinc-950 border border-zinc-700 rounded-lg px-3 py-2 text-sm text-zinc-300"
          placeholder={t('placeholderRevision')}
        />
        <button
          type="button"
          onClick={() => void runRevise()}
          disabled={busy !== null || !htmlFr.trim()}
          className="inline-flex items-center gap-2 rounded-lg bg-violet-500/25 border border-violet-500/40 hover:bg-violet-500/35 disabled:opacity-50 text-violet-100 text-xs font-medium px-3 py-2"
        >
          {busy === 'revise' ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Wand2 className="w-3.5 h-3.5" />}
          {t('buttonRevise')}
        </button>
      </div>

      <div className="rounded-xl border border-sky-900/40 bg-sky-950/20 p-4 space-y-2">
        <p className="text-[11px] font-semibold text-sky-300/90 uppercase tracking-wide flex items-center gap-2">
          <CalendarClock className="w-3.5 h-3.5" aria-hidden />
          {t('scheduleTitle')}
        </p>
        <p className="text-[10px] text-zinc-500">
          {t.rich('scheduleHelpRich', {
            browser: (chunks) => <strong className="text-zinc-400">{chunks}</strong>,
            cron: (chunks) => <code className="text-zinc-600">{chunks}</code>,
          })}
        </p>
        <input
          type="datetime-local"
          value={scheduleLocal}
          onChange={(e) => setScheduleLocal(e.target.value)}
          className="w-full max-w-md bg-zinc-950 border border-zinc-700 rounded-lg px-3 py-2 text-sm text-zinc-100"
        />
        <button
          type="button"
          onClick={() => void runSchedule()}
          disabled={busy !== null || !subjectFr.trim() || !htmlFr.trim()}
          className="inline-flex items-center gap-2 rounded-lg bg-sky-600/90 hover:bg-sky-600 disabled:opacity-50 text-white text-xs font-medium px-3 py-2"
        >
          {busy === 'schedule' ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <CalendarClock className="w-3.5 h-3.5" />}
          {t('buttonSchedule')}
        </button>
      </div>

      <div className="flex flex-wrap gap-2 pt-2 border-t border-zinc-800/60">
        <button
          type="button"
          onClick={() => void runTest()}
          disabled={busy !== null || !subjectFr.trim() || !htmlFr.trim()}
          className="inline-flex items-center gap-2 rounded-lg bg-amber-600/90 hover:bg-amber-600 disabled:opacity-50 text-white text-xs font-medium px-3 py-2"
        >
          {busy === 'test' ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Mail className="w-3.5 h-3.5" />}
          {t('buttonTest')}
        </button>
        <button
          type="button"
          onClick={() => void runSendAll()}
          disabled={busy !== null || !canSendAll}
          className="inline-flex items-center gap-2 rounded-lg bg-emerald-600/90 hover:bg-emerald-600 disabled:opacity-50 text-white text-xs font-medium px-3 py-2"
          title={!canSendAll ? t('sendAllDisabledTitle') : undefined}
        >
          {busy === 'send_all' ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Send className="w-3.5 h-3.5" />}
          {canSendAll ? <Unlock className="w-3 h-3" /> : <Lock className="w-3 h-3" />}
          {t('buttonSendAll')}
        </button>
      </div>

      {fingerprint && (
        <p className="text-[10px] text-zinc-500 font-mono break-all">
          {t('fingerprintPrefix')}
          {fingerprint.slice(0, 24)}…{' '}
          {contentMatchesTest ? (
            <span className="text-emerald-500">{t('fingerprintMatchNote')}</span>
          ) : (
            <span className="text-amber-500">{t('fingerprintMismatchNote')}</span>
          )}
        </p>
      )}
    </div>
  );
}

'use client';

import { useCallback, useEffect, useMemo, useState, type ReactNode } from 'react';
import { createPortal } from 'react-dom';
import {
  X,
  Loader2,
  Copy,
  Check,
  UserCircle,
  Search,
  Building2,
  ClipboardList,
  FileCheck,
  Wallet,
  AlertTriangle,
  Trash2,
  Mail,
  Phone,
  MapPin,
} from 'lucide-react';
import { toast } from 'sonner';
import { useFormatter, useLocale, useTranslations } from 'next-intl';
import { MERCHANT_ERASURE_CONFIRM } from '@/lib/admin/merchant-hard-erasure';

const COMPLIANCE_PROOF_DATETIME: Intl.DateTimeFormatOptions = {
  dateStyle: 'short',
  timeStyle: 'short',
};

const CONSENT_ROW_DATETIME: Intl.DateTimeFormatOptions = {
  day: '2-digit',
  month: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
};

type ConsentRow = {
  id: string;
  created_at: string;
  consent_type: string;
  channel: string;
  message_preview: string | null;
  metadata: Record<string, unknown> | null;
};

type EstablishmentRow = Record<string, unknown>;

type AiBudgetPayload = {
  period_start: string;
  call_count: number;
  daily_soft_limit: number;
  daily_hard_limit: number;
  updated_at: string;
} | null;

type ClientDetailResponse = {
  profile: Record<string, unknown>;
  ai_budget?: AiBudgetPayload;
  auth_user: {
    email?: string;
    email_confirmed_at?: string;
    last_sign_in_at?: string;
    created_at?: string;
    phone?: string;
  } | null;
  consent_logs?: ConsentRow[];
  establishments?: EstablishmentRow[];
  error?: string;
};

function formatDetailValue(
  t: (key: string) => string,
  key: string,
  value: unknown,
): ReactNode {
  if (value === null || value === undefined) {
    return <span className="text-zinc-600">{t('dashEmpty')}</span>;
  }
  if (typeof value === 'boolean') {
    return <span className="text-zinc-300">{value ? t('boolYes') : t('boolNo')}</span>;
  }
  if (typeof value === 'number') {
    return <span className="font-mono text-zinc-300 tabular-nums">{String(value)}</span>;
  }
  if (typeof value === 'object') {
    return (
      <pre className="text-[11px] font-mono text-zinc-400 whitespace-pre-wrap break-all max-h-40 overflow-y-auto rounded-lg border border-zinc-800 bg-zinc-950/80 p-2">
        {JSON.stringify(value, null, 2)}
      </pre>
    );
  }
  const s = String(value);
  const isSecret =
    /^(api_key|webhook_token|google_access_token|google_refresh_token)$/i.test(key) ||
    key.includes('secret');
  return (
    <span className={`text-xs break-all ${isSecret ? 'font-mono text-amber-200/90' : 'text-zinc-300'}`}>
      {s || t('dashEmpty')}
    </span>
  );
}

function CopyField({ value, copyTitle }: { value: string; copyTitle: string }) {
  const [done, setDone] = useState(false);
  const copy = () => {
    void navigator.clipboard.writeText(value).then(() => {
      setDone(true);
      setTimeout(() => setDone(false), 2000);
    });
  };
  return (
    <button
      type="button"
      onClick={copy}
      className="inline-flex items-center gap-1 rounded-md border border-zinc-700 px-1.5 py-0.5 text-[10px] text-zinc-400 hover:bg-zinc-800 hover:text-zinc-200 transition-colors"
      title={copyTitle}
    >
      {done ? <Check className="w-3 h-3 text-emerald-400" /> : <Copy className="w-3 h-3" />}
    </button>
  );
}

function FieldRows({
  data,
  title,
  query,
  t,
  sortLocale,
}: {
  data: Record<string, unknown>;
  title: string;
  query: string;
  t: (key: string) => string;
  sortLocale: string;
}) {
  const entries = useMemo(() => {
    const base = Object.entries(data).sort(([a], [b]) => a.localeCompare(b, sortLocale));
    const q = query.trim().toLowerCase();
    if (!q) return base;
    return base.filter(([k, v]) => {
      const sv = typeof v === 'object' && v !== null ? JSON.stringify(v) : String(v ?? '');
      return k.toLowerCase().includes(q) || sv.toLowerCase().includes(q);
    });
  }, [data, query, sortLocale]);

  if (entries.length === 0) {
    return (
      <div className="space-y-2">
        <h3 className="text-[11px] font-semibold uppercase tracking-wider text-zinc-500">{title}</h3>
        <p className="text-xs text-zinc-600">{t('fieldRowsEmpty')}</p>
      </div>
    );
  }

  return (
    <div className="space-y-3">
      <h3 className="text-[11px] font-semibold uppercase tracking-wider text-zinc-500">{title}</h3>
      <dl className="space-y-2.5">
        {entries.map(([key, value]) => {
          const str =
            typeof value === 'object' && value !== null
              ? JSON.stringify(value)
              : value === null || value === undefined
                ? ''
                : String(value);
          const showCopy =
            str.length > 0 &&
            (key === 'api_key' ||
              key === 'webhook_token' ||
              key.includes('token') ||
              key.includes('secret') ||
              str.length > 80);
          return (
            <div key={key} className="border-b border-zinc-800/60 pb-2.5 last:border-0 last:pb-0">
              <dt className="text-[10px] font-mono text-zinc-500 mb-1">{key}</dt>
              <dd className="flex items-start gap-2 justify-between">
                <div className="min-w-0 flex-1">{formatDetailValue(t, key, value)}</div>
                {showCopy && str.length > 0 && <CopyField value={str} copyTitle={t('copyTitle')} />}
              </dd>
            </div>
          );
        })}
      </dl>
    </div>
  );
}

function matchesQuery(q: string, ...parts: (string | null | undefined)[]) {
  if (!q.trim()) return true;
  const low = q.trim().toLowerCase();
  return parts.some((p) => (p ?? '').toLowerCase().includes(low));
}

export function AdminClientDetailSheet({
  clientId,
  establishmentLabel,
  onClose,
}: {
  clientId: string | null;
  establishmentLabel?: string | null;
  onClose: () => void;
}) {
  const t = useTranslations('Dashboard.adminClientDetail');
  const format = useFormatter();
  const locale = useLocale();
  const [mounted, setMounted] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [payload, setPayload] = useState<ClientDetailResponse | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [softLimitInput, setSoftLimitInput] = useState('400');
  const [hardLimitInput, setHardLimitInput] = useState('7000');
  const [savingBudget, setSavingBudget] = useState(false);
  const [erasePhrase, setErasePhrase] = useState('');
  const [erasing, setErasing] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  const load = useCallback(async () => {
    if (!clientId) return;
    setLoading(true);
    setError(null);
    setPayload(null);
    try {
      const res = await fetch(`/api/admin/clients/${clientId}`, { credentials: 'same-origin' });
      const json = (await res.json()) as ClientDetailResponse & { error?: string };
      if (!res.ok) {
        throw new Error(json.error ?? `HTTP ${res.status}`);
      }
      setPayload(json);
    } catch (e) {
      setError(e instanceof Error ? e.message : t('errLoad'));
    } finally {
      setLoading(false);
    }
  }, [clientId, t]);

  useEffect(() => {
    if (clientId) void load();
  }, [clientId, load]);

  const saveBudget = async () => {
    if (!clientId) return;
    const soft = parseInt(softLimitInput, 10);
    const hard = parseInt(hardLimitInput, 10);
    if (!Number.isFinite(soft) || !Number.isFinite(hard) || soft < 1 || hard < soft + 1) {
      toast.error(t('toastBudgetInvalid'));
      return;
    }
    setSavingBudget(true);
    try {
      const r = await fetch(`/api/admin/clients/${clientId}/ai-budget`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ daily_soft_limit: soft, daily_hard_limit: hard }),
      });
      const j = (await r.json()) as { error?: string };
      if (!r.ok) throw new Error(j.error ?? t('errGeneric'));
      toast.success(t('toastBudgetOk'));
      await load();
    } catch (e) {
      toast.error(e instanceof Error ? e.message : t('errGeneric'));
    } finally {
      setSavingBudget(false);
    }
  };

  const runHardErase = async () => {
    if (!clientId) return;
    setErasing(true);
    try {
      const r = await fetch(`/api/admin/clients/${clientId}/hard-erasure`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ confirm: erasePhrase }),
      });
      const j = (await r.json()) as { error?: string; notes?: string[] };
      if (!r.ok) throw new Error(j.error ?? t('errGeneric'));
      toast.success(t('toastEraseOk'));
      setErasePhrase('');
      onClose();
    } catch (e) {
      toast.error(e instanceof Error ? e.message : t('errGeneric'));
    } finally {
      setErasing(false);
    }
  };

  useEffect(() => {
    if (!clientId) return;
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    window.addEventListener('keydown', onKey);
    const prev = document.body.style.overflow;
    document.body.style.overflow = 'hidden';
    return () => {
      window.removeEventListener('keydown', onKey);
      document.body.style.overflow = prev;
    };
  }, [clientId, onClose]);

  useEffect(() => {
    if (!clientId) setSearchQuery('');
  }, [clientId]);

  useEffect(() => {
    const b = payload?.ai_budget;
    if (b && typeof b.daily_soft_limit === 'number' && typeof b.daily_hard_limit === 'number') {
      setSoftLimitInput(String(b.daily_soft_limit));
      setHardLimitInput(String(b.daily_hard_limit));
    }
  }, [payload?.ai_budget, clientId]);

  const q = searchQuery.trim().toLowerCase();

  const filteredEstablishments = useMemo(() => {
    const list = payload?.establishments ?? [];
    if (!q) return list;
    return list.filter((row) => {
      const name = String(row.name ?? '');
      const addr = String(row.address ?? '');
      const gl = String(row.google_location_name ?? '');
      return matchesQuery(searchQuery, name, addr, gl, String(row.id ?? ''));
    });
  }, [payload?.establishments, searchQuery, q]);

  const filteredConsentLogs = useMemo(() => {
    const list = payload?.consent_logs ?? [];
    if (!q) return list;
    return list.filter((row) =>
      matchesQuery(searchQuery, row.consent_type, row.channel, row.message_preview ?? '', row.id)
    );
  }, [payload?.consent_logs, searchQuery, q]);

  if (!clientId || !mounted) return null;

  const overlay = (
    <button
      type="button"
      aria-hidden
      className="fixed inset-0 z-[10000] bg-black/60 backdrop-blur-sm"
      onClick={onClose}
    />
  );

  const panel = (
    <aside
      className="fixed inset-y-0 right-0 z-[10001] flex w-full max-w-lg flex-col border-l border-zinc-800 bg-zinc-950 shadow-2xl pt-[env(safe-area-inset-top)]"
      role="dialog"
      aria-modal="true"
      aria-labelledby="admin-client-sheet-title"
    >
      <div className="flex items-start justify-between gap-3 border-b border-zinc-800 px-4 py-3 flex-shrink-0">
        <div className="min-w-0 flex items-start gap-3">
          <div className="flex h-10 w-10 flex-shrink-0 items-center justify-center rounded-xl border border-zinc-700 bg-zinc-900">
            <UserCircle className="h-5 w-5 text-zinc-400" />
          </div>
          <div>
            <h2 id="admin-client-sheet-title" className="text-sm font-semibold text-zinc-100 truncate pr-2">
              {t('sheetTitle')}
            </h2>
            <p className="text-xs text-zinc-500 mt-0.5 truncate">{establishmentLabel || t('dashEmpty')}</p>
            <p className="text-[10px] font-mono text-zinc-600 mt-1 break-all">{clientId}</p>
          </div>
        </div>
        <button
          type="button"
          onClick={onClose}
          className="rounded-lg p-2 text-zinc-500 hover:bg-zinc-800 hover:text-zinc-200 transition-colors"
          aria-label={t('closeAria')}
        >
          <X className="h-5 w-5" />
        </button>
      </div>

      <div className="px-4 py-2 border-b border-zinc-800 flex-shrink-0">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-500 pointer-events-none" />
          <input
            type="search"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            placeholder={t('filterPlaceholder')}
            className="w-full rounded-xl border border-zinc-700 bg-zinc-900/80 pl-9 pr-3 py-2 text-sm text-zinc-100 placeholder:text-zinc-600 focus:outline-none focus:ring-2 focus:ring-blue-500/30 focus:border-blue-500/50"
            autoComplete="off"
          />
        </div>
      </div>

      <div className="flex-1 overflow-y-auto px-4 py-4 min-h-0">
        {loading && (
          <div className="flex flex-col items-center justify-center py-16 gap-2 text-zinc-500">
            <Loader2 className="h-8 w-8 animate-spin text-zinc-600" />
