              <div className="flex flex-wrap gap-2 items-end">
                <label className="flex flex-col gap-1 text-[10px] text-zinc-500">
                  {t('softPerDay')}
                  <input
                    type="number"
                    min={1}
                    value={softLimitInput}
                    onChange={(e) => setSoftLimitInput(e.target.value)}
