                  />
                </label>
                <label className="flex flex-col gap-1 text-[10px] text-zinc-500">
                  {t('hardPerDay')}
                  <input
                    type="number"
                    min={2}
                    value={hardLimitInput}
                    onChange={(e) => setHardLimitInput(e.target.value)}
