                <button
                  type="button"
                  disabled={savingBudget}
                  onClick={() => void saveBudget()}
                  className="rounded-lg bg-amber-600/80 hover:bg-amber-500/90 text-white text-[11px] font-semibold px-3 py-2 disabled:opacity-40"
                >
