function latLngToXY(lat: number, lng: number, w: number, h: number) {
  const x = ((lng + 180) / 360) * w;
  const y = ((90 - lat) / 180) * h;
  return { x, y };
}

const PHASE_COLORS: Record<string, string> = {
  scanned: 'bg-zinc-500',
