const VAULT_STALE_MS = 40 * 60 * 60 * 1000;

/** Intl options hoisted for ESLint (i18next/no-literal-string in JSX). */
const UTC_JOURNAL_ROW_DATETIME: Intl.DateTimeFormatOptions = {
