function formatPilotageEur(cents: number, locale: string): string {
  return new Intl.NumberFormat(locale, {
    style: 'currency',
    currency: 'EUR',
    maximumFractionDigits: cents % 100 === 0 ? 0 : 2,
  }).format(cents / 100);
}

type ActivityCursor = { created_at: string; id: string };

type StaffStatApiRow = {
  id: string;
  display_name: string;
  is_active: boolean;
  clientsCreated: number;
  revenueCents: number;
  googlePositiveReviews: number;
  ticketsEncaisse: number;
  transformPercent: number;
  avgBasketCents: number;
};

const ACTIVITY_PAGE = 15;
const STAFF_TABLE_PAGE = 6;
const CAISSE_TABLE_PAGE = 7;

const INTL_MONTH_LONG_OPTS = { month: 'long' as const };

function heatWeekdayIntensityClass(intensity: number): string {
  if (intensity < 0.08) return 'bg-slate-100 dark:bg-zinc-800';
  if (intensity < 0.35) return 'bg-emerald-200/90 dark:bg-emerald-900/50';
  if (intensity < 0.65) return 'bg-emerald-500/85 dark:bg-emerald-700/70';
  return 'bg-emerald-700 dark:bg-emerald-600';
}

type RetentionModalKey = 'new' | 'returned' | 'vip';

function RetentionFunnelCompareChart({
  snapshot,
  active,
}: {
  snapshot: RetentionFunnelSnapshot;
  active: RetentionModalKey;
}) {
  const t = useTranslations('Dashboard.bananoOmnipresent');
  const items: { key: RetentionModalKey; label: string; v: number }[] = useMemo(
    () => [
      { key: 'new', label: t('funnelNew'), v: snapshot.newClientsThisMonth },
      { key: 'returned', label: t('funnelReturned'), v: snapshot.returnedAtLeastTwiceThisMonth },
      { key: 'vip', label: t('funnelVip'), v: snapshot.vipProfilesCount },
    ],
    [t, snapshot]
  );
  const max = Math.max(1, ...items.map((i) => i.v));
  return (
    <div className="space-y-2">
      <p className="text-[11px] font-semibold text-violet-800 dark:text-violet-200">
        {t('funnelCompareTitle')}
      </p>
      <div className="space-y-2">
        {items.map((it) => (
          <div key={it.key} className="flex items-center gap-2 text-[11px] min-w-0">
            <span
              className={`w-[9.5rem] shrink-0 truncate ${
                it.key === active
                  ? 'font-bold text-violet-700 dark:text-violet-300'
                  : 'text-slate-600 dark:text-slate-400'
              }`}
            >
              {it.label}
            </span>
            <div className="flex-1 min-w-0 h-6 rounded bg-slate-100 dark:bg-zinc-800 overflow-hidden">
              <div
                className={`h-full rounded transition-all ${
                  it.key === active ? 'bg-violet-500' : 'bg-emerald-500/75'
                }`}
                style={{ width: `${Math.min(100, (it.v / max) * 100)}%` }}
              />
            </div>
            <span className="tabular-nums font-semibold w-7 shrink-0 text-right text-slate-800 dark:text-slate-100">
              {it.v}
            </span>
          </div>
        ))}
      </div>
    </div>
  );
}

const RETENTION_MODAL_PAGE_SIZE = 10;

function RetentionListPagination({
  page,
  total,
  pageSize,
  onPage,
}: {
  page: number;
  total: number;
  pageSize: number;
  onPage: (p: number) => void;
}) {
  const t = useTranslations('Dashboard.bananoOmnipresent');
  const pageCount = Math.max(1, Math.ceil(total / pageSize));
  const safePage = Math.min(Math.max(0, page), pageCount - 1);
  if (total <= pageSize) return null;
  return (
    <div className="flex items-center justify-between gap-2 pt-3 border-t border-slate-100 dark:border-zinc-800 text-[11px] text-slate-600 dark:text-slate-400">
      <button
        type="button"
        disabled={safePage <= 0}
        onClick={() => onPage(safePage - 1)}
        className="min-h-[36px] px-2.5 rounded-lg border border-slate-200 dark:border-zinc-700 font-semibold disabled:opacity-40"
      >
        {t('pagePrev')}
      </button>
      <span className="tabular-nums text-center shrink-0">
        {safePage + 1} / {pageCount}
        <span className="text-slate-400 dark:text-slate-500"> ({total})</span>
      </span>
      <button
        type="button"
        disabled={safePage >= pageCount - 1}
        onClick={() => onPage(safePage + 1)}
        className="min-h-[36px] px-2.5 rounded-lg border border-slate-200 dark:border-zinc-700 font-semibold disabled:opacity-40"
      >
        {t('pageNext')}
      </button>
    </div>
  );
}

export function BananoOmnipresentDashboard() {
  const locale = useLocale();
  const t = useTranslations('Dashboard.bananoOmnipresent');
  const [view, setView] = useState<TemporalViewKey>('day');
  const [data, setData] = useState<PilotageDashboardPayload | null>(null);
  const [loading, setLoading] = useState(true);
  const [err, setErr] = useState<string | null>(null);
  const [relaunchBusy, setRelaunchBusy] = useState(false);
  const [staffRows, setStaffRows] = useState<StaffStatApiRow[]>([]);
  const [staffStatsDisclaimer, setStaffStatsDisclaimer] = useState<string | null>(null);
  const [staffStatsLoading, setStaffStatsLoading] = useState(true);
  const [staffPageIdx, setStaffPageIdx] = useState(0);
  const [staffStatsYear, setStaffStatsYear] = useState(() => String(new Date().getFullYear()));
  const [staffStatsMonth, setStaffStatsMonth] = useState(() =>
    String(new Date().getMonth() + 1).padStart(2, '0')
  );
  const [staffPeriodLabel, setStaffPeriodLabel] = useState<string | null>(null);
  const [activityLines, setActivityLines] = useState<{ at: string; line: string }[]>([]);
  const [activityLoading, setActivityLoading] = useState(true);
  const [activityTotal, setActivityTotal] = useState(0);
  /** `afterStack[p]` = curseur API après la page p (ligne la plus ancienne du lot). */
  const activityAfterStackRef = useRef<(ActivityCursor | null)[]>([]);
  const [activityPageIdx, setActivityPageIdx] = useState(0);
  const [activityHasOlder, setActivityHasOlder] = useState(false);
  const [retentionModal, setRetentionModal] = useState<RetentionModalKey | null>(null);
  const [retentionDetailPage, setRetentionDetailPage] = useState(0);
  const [archiveExportYear, setArchiveExportYear] = useState(() =>
    String(new Date().getFullYear())
  );
  const [archiveExportMonth, setArchiveExportMonth] = useState(() =>
    String(new Date().getMonth() + 1).padStart(2, '0')
  );
  const [cashExplorerOpen, setCashExplorerOpen] = useState(false);
  const [caissePageIdx, setCaissePageIdx] = useState(0);
  const [voucherMonthArchives, setVoucherMonthArchives] = useState<{
    loyalty: VoucherMonthArchiveListItem[];
    staff: VoucherMonthArchiveListItem[];
  }>({ loyalty: [], staff: [] });

  const temporalTabs = useMemo(
    () =>
      [
        { key: 'day' as const, label: t('tabDay'), hint: t('tabDayHint') },
        { key: 'week' as const, label: t('tabWeek'), hint: t('tabWeekHint') },
        { key: 'month' as const, label: t('tabMonth'), hint: t('tabMonthHint') },
      ] as const,
    [t]
  );

  const weekdayFmt = useMemo(
    () => new Intl.DateTimeFormat(locale, { weekday: 'short' }),
    [locale]
  );

  const loadPilotage = useCallback(async () => {
    setLoading(true);
    setErr(null);
    try {
      const r = await fetch(`/api/banano/pilotage?locale=${encodeURIComponent(locale)}`);
      const json = (await r.json()) as PilotageDashboardPayload & { error?: string };
      if (json.error) {
        setData(null);
        setErr(json.error);
        return;
      }
      if (!json.temporal || !json.smartCards || !Array.isArray(json.reports)) {
        setErr(t('errInvalidResponse'));
        setData(null);
        return;
      }
      setData({
        ...json,
        retentionFunnel: json.retentionFunnel ?? {
          newClientsThisMonth: 0,
          returnedAtLeastTwiceThisMonth: 0,
          vipProfilesCount: 0,
        },
        retentionFunnelDetail: json.retentionFunnelDetail ?? {
          newMembers: [],
          returnedTwice: [],
          vipProfiles: [],
        },
        weekdayHeat: Array.isArray(json.weekdayHeat) ? json.weekdayHeat : [],
        monthlyFinancial: json.monthlyFinancial
          ? {
              ...json.monthlyFinancial,
              forecastLine:
                json.monthlyFinancial.forecastLine ?? t('forecastUnavailable'),
            }
          : null,
      });
    } catch {
      setErr(t('errLoadPilotage'));
      setData(null);
    } finally {
      setLoading(false);
    }
  }, [locale, t]);

  const loadVoucherMonthArchives = useCallback(async () => {
    try {
      const r = await fetch('/api/banano/crm/voucher-month-archives/list');
      const j = (await r.json()) as {
        loyalty?: VoucherMonthArchiveListItem[];
        staff?: VoucherMonthArchiveListItem[];
        error?: string;
      };
      if (!r.ok) return;
      setVoucherMonthArchives({
        loyalty: j.loyalty ?? [],
        staff: j.staff ?? [],
      });
    } catch {
      /* ignore */
    }
  }, []);

  useEffect(() => {
    void loadPilotage();
  }, [loadPilotage]);

  useEffect(() => {
    void loadVoucherMonthArchives();
  }, [loadVoucherMonthArchives]);

  useEffect(() => {
    setCaissePageIdx(0);
  }, [data]);

  const loadStaffStats = useCallback(async () => {
    setStaffStatsLoading(true);
    try {
      const qs = new URLSearchParams({
        year: staffStatsYear.trim(),
        month: String(parseInt(staffStatsMonth, 10)),
      });
      const qsLocale = new URLSearchParams(qs);
      qsLocale.set('locale', locale);
      const sRes = await fetch(`/api/banano/staff/stats?${qsLocale.toString()}`);
      const sJson = (await sRes.json()) as {
        rows?: StaffStatApiRow[];
        disclaimer?: string;
        periodLabel?: string;
        periodLabelFr?: string;
        error?: string;
      };
      if (sRes.ok && sJson.rows) {
        setStaffRows(sJson.rows);
        setStaffStatsDisclaimer(sJson.rows.length > 0 ? t('staffGoogleDisclaimer') : null);
        const pl = sJson.periodLabel ?? sJson.periodLabelFr;
        setStaffPeriodLabel(typeof pl === 'string' ? pl : null);
      } else {
        setStaffRows([]);
        setStaffStatsDisclaimer(null);
        setStaffPeriodLabel(null);
      }
    } catch {
      setStaffRows([]);
      setStaffStatsDisclaimer(null);
      setStaffPeriodLabel(null);
    } finally {
      setStaffStatsLoading(false);
    }
  }, [staffStatsYear, staffStatsMonth, locale, t]);

  const loadActivityFeed = useCallback(async () => {
    setActivityLoading(true);
    try {
      const stack = activityAfterStackRef.current;
      let after: ActivityCursor | null = null;

      for (let p = 0; p <= activityPageIdx; p++) {
        if (p < activityPageIdx) {
          const cached = stack[p];
          if (cached === null) {
            setActivityPageIdx(Math.max(0, p));
            setActivityLines([]);
            setActivityTotal(0);
            setActivityHasOlder(false);
            return;
          }
          if (cached !== undefined) {
            after = cached;
            continue;
          }
        }

        const params = new URLSearchParams({ limit: String(ACTIVITY_PAGE) });
        params.set('uiLocale', locale);
        if (after) {
          params.set('afterCreatedAt', after.created_at);
          params.set('afterId', after.id);
        }
        const aRes = await fetch(`/api/banano/activity-feed?${params.toString()}`);
        const aJson = (await aRes.json()) as {
          items?: { at: string; line: string }[];
          total?: number;
          nextCursor?: ActivityCursor | null;
          error?: string;
        };
        if (!aRes.ok || !aJson.items) {
          setActivityLines([]);
          setActivityTotal(0);
          setActivityHasOlder(false);
          return;
        }
        stack[p] = aJson.nextCursor ?? null;
        if (p === activityPageIdx) {
          setActivityLines(aJson.items);
          setActivityTotal(typeof aJson.total === 'number' ? aJson.total : aJson.items.length);
          setActivityHasOlder(Boolean(aJson.nextCursor));
        }
        after = stack[p];
        if (!after && p < activityPageIdx) {
          setActivityPageIdx(Math.max(0, p));
          setActivityHasOlder(false);
          return;
        }
      }
    } catch {
      setActivityLines([]);
      setActivityTotal(0);
      setActivityHasOlder(false);
    } finally {
      setActivityLoading(false);
    }
  }, [activityPageIdx, locale]);

  useEffect(() => {
    void loadStaffStats();
  }, [loadStaffStats]);

  useEffect(() => {
    void loadActivityFeed();
  }, [loadActivityFeed]);

  useEffect(() => {
    const last = Math.max(0, Math.ceil(staffRows.length / STAFF_TABLE_PAGE) - 1);
    setStaffPageIdx((idx) => (idx > last ? last : idx));
  }, [staffRows.length]);

  useEffect(() => {
    let debounce: ReturnType<typeof setTimeout> | undefined;
    const onVis = () => {
      if (document.visibilityState !== 'visible') return;
      if (debounce) clearTimeout(debounce);
      debounce = setTimeout(() => {
        debounce = undefined;
        void Promise.all([loadPilotage(), loadStaffStats(), loadActivityFeed()]);
      }, 400);
    };
    document.addEventListener('visibilitychange', onVis);
    return () => {
      if (debounce) clearTimeout(debounce);
      document.removeEventListener('visibilitychange', onVis);
    };
  }, [loadPilotage, loadStaffStats, loadActivityFeed]);

  async function sendRiskWhatsAppRelaunch() {
    setRelaunchBusy(true);
    try {
      const res = await fetch('/api/banano/pilotage/relaunch-whatsapp', { method: 'POST' });
      const json = (await res.json()) as {
        ok?: boolean;
        sent?: number;
        failed?: number;
        skippedCooldown?: number;
        errors?: string[];
        error?: string;
      };
      if (!res.ok) {
        throw new Error(json.error ?? t('errSendImpossible'));
      }
      const sent = json.sent ?? 0;
      const failed = json.failed ?? 0;
      const skipped = json.skippedCooldown ?? 0;

      if (sent > 0) {
        toast.success(t('toastWaSent', { count: sent }), {
          description: skipped > 0 ? t('toastWaSkippedDesc', { skipped }) : undefined,
        });
      } else if (skipped > 0 && failed === 0) {
        toast.message(t('toastWaAllSkipped'));
      } else if (failed > 0) {
        toast.error(json.errors?.[0] ?? t('toastWaFailed'));
      } else {
        toast.message(t('toastWaNoTargets'));
      }

      await loadPilotage();
    } catch (e) {
      toast.error(e instanceof Error ? e.message : t('errGeneric'));
    } finally {
      setRelaunchBusy(false);
    }
  }

  const traceabilityMonthLinks = useMemo(() => {
    const out: { ym: string; label: string }[] = [];
    const d = new Date();
    for (let i = 1; i <= 6; i++) {
      const monthDate = new Date(d.getFullYear(), d.getMonth() - i, 1);
      out.push({
        ym: `${monthDate.getFullYear()}-${String(monthDate.getMonth() + 1).padStart(2, '0')}`,
        label: monthDate.toLocaleDateString(locale, { month: 'long', year: 'numeric' }),
      });
    }
    return out;
  }, [locale]);

  const staffSliceStart = staffPageIdx * STAFF_TABLE_PAGE;
  const staffPageRows = useMemo(
    () => staffRows.slice(staffSliceStart, staffSliceStart + STAFF_TABLE_PAGE),
    [staffRows, staffSliceStart]
  );
  const staffPageCount = Math.max(1, Math.ceil(staffRows.length / STAFF_TABLE_PAGE) || 1);

  const heatMax = useMemo(() => {
    const cells = data?.weekdayHeat ?? [];
    if (!cells.length) return 1;
    return Math.max(1, ...cells.map((c) => c.count));
  }, [data?.weekdayHeat]);

  const returnedTwiceSorted = useMemo(() => {
    const rows = data?.retentionFunnelDetail?.returnedTwice ?? [];
    return [...rows].sort((a, b) => b.visitsInMonth - a.visitsInMonth);
  }, [data?.retentionFunnelDetail?.returnedTwice]);

  const vipProfilesSorted = useMemo(() => {
    const rows = data?.retentionFunnelDetail?.vipProfiles ?? [];
    return [...rows].sort((a, b) => b.lifetimeVisits - a.lifetimeVisits);
  }, [data?.retentionFunnelDetail?.vipProfiles]);

  useEffect(() => {
    setRetentionDetailPage(0);
  }, [retentionModal]);

  const activityPageCount = Math.max(1, Math.ceil(activityTotal / ACTIVITY_PAGE) || 1);
  const currentActivityPage = activityPageIdx + 1;

  const block = data?.temporal?.[view] ?? null;
  const updatedLabel = useMemo(() => {
    if (!data?.generatedAt) return null;
    return new Date(data.generatedAt).toLocaleString(locale, {
      dateStyle: 'short',
      timeStyle: 'short',
    });
  }, [data?.generatedAt, locale]);

  return (
    <div className="space-y-6 sm:space-y-8 max-w-full overflow-x-hidden">
      <header className="space-y-1">
        <div className="flex items-center gap-2 text-[#2563eb]">
          <BarChart3 className="w-5 h-5 shrink-0" />
          <h2 className="text-xl font-display font-bold text-slate-900 dark:text-slate-50">
            {t('title')}
          </h2>
        </div>
        <p className="text-sm text-slate-500 dark:text-slate-400 max-w-2xl leading-relaxed">{t('subtitle')}</p>
        {updatedLabel ? (
          <p className="text-xs text-slate-400 dark:text-slate-500">{t('lastUpdated', { date: updatedLabel })}</p>
        ) : null}
      </header>

      <section
        className="rounded-2xl border border-indigo-200/80 dark:border-indigo-900/40 bg-indigo-50/35 dark:bg-indigo-950/20 p-4 sm:p-6 shadow-sm space-y-4"
        aria-label={t('ariaStaffPerformance')}
      >
        <div className="flex items-center gap-2 text-indigo-800 dark:text-indigo-200">
          <Users className="w-5 h-5 shrink-0" />
          <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between min-w-0 flex-1">
            <h3 className="text-sm font-bold text-slate-900 dark:text-slate-50 uppercase tracking-wide shrink-0">
              {t('staffTitle')}
            </h3>
            <div className="flex flex-wrap items-end gap-2 text-xs">
              <label className="text-indigo-950 dark:text-indigo-100/90 font-medium">
                {t('monthLabel')}
                <select
                  value={staffStatsMonth}
                  onChange={(e) => setStaffStatsMonth(e.target.value)}
                  className="mt-1 ml-1 min-h-[36px] px-2 rounded-lg border border-indigo-200/80 dark:border-zinc-600 bg-white dark:bg-zinc-950 tabular-nums"
                >
                  {Array.from({ length: 12 }, (_, i) => {
                    const m = String(i + 1).padStart(2, '0');
                    return (
                      <option key={m} value={m}>
                        {new Date(2000, i, 1).toLocaleDateString(locale, INTL_MONTH_LONG_OPTS)}
                      </option>
                    );
                  })}
                </select>
              </label>
              <label className="text-indigo-950 dark:text-indigo-100/90 font-medium">
                {t('yearLabel')}
                <input
                  type="number"
                  min={2018}
                  max={new Date().getFullYear()}
                  value={staffStatsYear}
                  onChange={(e) => setStaffStatsYear(e.target.value)}
                  className="mt-1 ml-1 w-[5.5rem] min-h-[36px] px-2 rounded-lg border border-indigo-200/80 dark:border-zinc-600 bg-white dark:bg-zinc-950 tabular-nums"
                />
              </label>
            </div>
          </div>
        </div>
        {staffPeriodLabel ? (
          <p className="text-xs font-semibold text-indigo-800 dark:text-indigo-200/90 capitalize">
            {t('periodPrefix', { label: staffPeriodLabel })}
          </p>
        ) : null}
        <p className="text-sm font-semibold text-indigo-900 dark:text-indigo-100 leading-snug">
