      const data = (await res.json()) as { ok?: boolean; error?: string };
      if (!res.ok) throw new Error(data.error ?? t('errFail'));
      toast.success(t('toastPinSaved'));
      setBoot((b) => (b ? { ...b, pinConfigured: true } : b));
      setPinA('');
      setPinB('');
