                        className="w-full min-h-[52px] rounded-2xl bg-[#2563eb] text-white font-semibold text-base flex items-center justify-center gap-2 hover:bg-[#1d4ed8] active:scale-[0.99] disabled:opacity-50 touch-manipulation"
                      >
