'use client';

import { useEffect, useState } from 'react';
import { createPortal } from 'react-dom';
import { Cake, Loader2, Sparkles, X } from 'lucide-react';
import { useLocale, useTranslations } from 'next-intl';
import { toast } from 'sonner';
import { WhatsAppMark } from '@/components/banano/whatsapp-mark';
import { isBirthdayToday } from '@/lib/banano/loyalty-timeline-labels';
import { siteLocaleToIntlDateTag } from '@/lib/i18n/site-locales-catalog';
import { useDashboardDisplayTimeZone } from '@/components/dashboard/dashboard-timezone-provider';

type MemberLite = {
  id: string;
  phone_e164: string;
  first_name?: string | null;
  last_name?: string | null;
  display_name?: string | null;
  birth_date?: string | null;
  /** Pour reformulation IA « mémoire client » (relance / absence). */
  last_visit_at?: string | null;
};

type Props = {
  member: MemberLite | null;
  onClose: () => void;
  onSent: () => void;
};

function greetingName(m: MemberLite): string {
  const f = (m.first_name ?? '').trim();
  if (f) return f;
  const d = (m.display_name ?? '').trim();
  if (d) return d.split(/\s+/)[0] ?? d;
  return '';
}

export function ManualWhatsAppComposerModal({ member, onClose, onSent }: Props) {
  const t = useTranslations('Dashboard.bananoManualWhatsapp');
  const locale = useLocale();
  const intlDate = siteLocaleToIntlDateTag(locale);
  const merchantDisplayTz = useDashboardDisplayTimeZone();
  const [draft, setDraft] = useState('');
  const [scheduleOn, setScheduleOn] = useState(false);
  /** Valeur pour input datetime-local (fuseau navigateur). */
  const [scheduleLocal, setScheduleLocal] = useState('');
  const [submitBusy, setSubmitBusy] = useState(false);
  const [rephraseBusy, setRephraseBusy] = useState(false);

  useEffect(() => {
    if (!member) {
      setDraft('');
      setScheduleOn(false);
      setScheduleLocal('');
      return;
    }
    const name = greetingName(member);
    setDraft(name ? t('draftGreeting', { name }) : '');
    setScheduleOn(false);
    setScheduleLocal('');
  }, [member, t]);

  async function rephrase() {
    const draftText = draft.trim();
    if (draftText.length < 3) {
      toast.error(t('toastDraftShort'));
      return;
    }
    setRephraseBusy(true);
    try {
      const loyalty_context = member
        ? (() => {
            const prenom = greetingName(member) || undefined;
            if (member.birth_date && isBirthdayToday(member.birth_date, merchantDisplayTz)) {
              return { scenario: 'birthday' as const, prenom };
            }
            if (member.last_visit_at) {
              const days = Math.floor(
                (Date.now() - new Date(member.last_visit_at).getTime()) / 86400000
              );
              if (days >= 14) {
                return { scenario: 'lost_client' as const, days_inactive: days, prenom };
              }
            }
            return { scenario: 'manual' as const, prenom };
          })()
        : undefined;
      const res = await fetch('/api/banano/crm/manual-whatsapp/rephrase', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ draft: draftText, loyalty_context }),
      });
      const data = (await res.json()) as { text?: string; error?: string };
      if (!res.ok) throw new Error(data.error ?? t('errGeneric'));
      if (data.text) {
        setDraft(data.text);
        toast.success(t('toastRephrased'));
      }
    } catch (e) {
      toast.error(e instanceof Error ? e.message : t('errGeneric'));
    } finally {
      setRephraseBusy(false);
    }
  }

  async function submit() {
    if (!member) return;
    const message = draft.trim();
    if (message.length < 1) {
      toast.error(t('toastEmpty'));
      return;
    }

    let scheduledAt: string | null = null;
    if (scheduleOn) {
      if (!scheduleLocal.trim()) {
        toast.error(t('toastPickSchedule'));
        return;
      }
      const ts = new Date(scheduleLocal).getTime();
      if (Number.isNaN(ts)) {
        toast.error(t('toastInvalidDate'));
        return;
      }
      if (ts <= Date.now() + 90_000) {
        toast.error(t('toastScheduleLead'));
        return;
      }
      scheduledAt = new Date(ts).toISOString();
    }

    setSubmitBusy(true);
    try {
      const res = await fetch('/api/banano/crm/manual-whatsapp', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          memberId: member.id,
          message,
          scheduledAt: scheduleOn ? scheduledAt : null,
        }),
      });
      const data = (await res.json()) as {
        ok?: boolean;
        mode?: string;
        error?: string;
        scheduledAt?: string;
      };
      if (!res.ok) throw new Error(data.error ?? t('errGeneric'));

      if (data.mode === 'scheduled') {
        toast.success(t('toastScheduled'), {
          description: data.scheduledAt
            ? new Date(data.scheduledAt).toLocaleString(intlDate, {
                dateStyle: 'short',
                timeStyle: 'short',
              })
            : undefined,
        });
      } else {
        toast.success(t('toastSent'));
      }
      onSent();
      onClose();
    } catch (e) {
      toast.error(e instanceof Error ? e.message : t('errGeneric'));
    } finally {
      setSubmitBusy(false);
    }
  }

  if (typeof document === 'undefined' || !member) return null;

  const name = greetingName(member);
  const bday = isBirthdayToday(member.birth_date, merchantDisplayTz);

  return createPortal(
    <div className="fixed inset-0 z-[200] flex items-center justify-center p-4">
      <button
        type="button"
        className="absolute inset-0 bg-black/50 backdrop-blur-[2px]"
        aria-label={t('close')}
        onClick={onClose}
      />
      <div
        role="dialog"
        aria-modal="true"
        aria-labelledby="manual-wa-title"
        className="relative w-full max-w-lg rounded-2xl border border-slate-200 dark:border-zinc-700 bg-white dark:bg-[#09090b] shadow-2xl flex flex-col max-h-[min(92vh,640px)]"
        onMouseDown={(e) => e.stopPropagation()}
      >
        <div className="shrink-0 flex items-start gap-3 p-4 border-b border-slate-200 dark:border-zinc-800">
          <div className="flex h-11 w-11 items-center justify-center rounded-xl bg-[#25D366]/15 text-[#25D366]">
            <WhatsAppMark className="w-6 h-6" />
          </div>
          <div className="min-w-0 flex-1">
            <h2 id="manual-wa-title" className="text-lg font-bold text-slate-900 dark:text-slate-50">
              {t('title')}
            </h2>
            <p className="text-sm text-slate-500 dark:text-slate-400 truncate">
              {name || t('customerFallback')}
              {t('customerMetaSeparator')}
              <span className="font-mono text-xs">{member.phone_e164}</span>
              {bday ? (
                <span className="ml-2 inline-flex items-center gap-0.5 text-amber-700 dark:text-amber-300 text-xs font-semibold">
                  <Cake className="w-3.5 h-3.5" />
                  {t('birthdayBadge')}
                </span>
              ) : null}
            </p>
          </div>
          <button
            type="button"
            onClick={onClose}
            className="shrink-0 p-2 rounded-xl hover:bg-slate-100 dark:hover:bg-zinc-800"
            aria-label={t('close')}
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="flex-1 min-h-0 overflow-y-auto p-4 space-y-4">
          <div>
            <label className="block text-xs font-semibold text-slate-500 dark:text-slate-400 mb-1.5">
              {t('yourMessage')}
            </label>
            <textarea
              value={draft}
              onChange={(e) => setDraft(e.target.value)}
              rows={8}
              className="w-full px-3 py-2.5 rounded-xl border border-slate-200 dark:border-zinc-700 bg-white dark:bg-zinc-950 text-slate-900 dark:text-slate-100 text-sm leading-relaxed resize-y min-h-[140px] focus:outline-none focus:ring-2 focus:ring-[#25D366]/35"
              placeholder={t('placeholder')}
              maxLength={4000}
            />
            <p className="text-[11px] text-slate-400 mt-1 tabular-nums">
              {t('draftCharCount', { current: draft.length, max: 4000 })}
            </p>
          </div>

          <button
            type="button"
            disabled={rephraseBusy || draft.trim().length < 3}
            onClick={() => void rephrase()}
            className="w-full min-h-[44px] inline-flex items-center justify-center gap-2 rounded-xl border border-indigo-200 dark:border-indigo-800/60 bg-indigo-50/80 dark:bg-indigo-950/30 text-indigo-800 dark:text-indigo-200 text-sm font-semibold hover:bg-indigo-100/90 dark:hover:bg-indigo-950/50 disabled:opacity-50"
          >
            {rephraseBusy ? <Loader2 className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />}
            {t('rephraseAi')}
          </button>

          <div className="rounded-xl border border-slate-200 dark:border-zinc-800 bg-slate-50/80 dark:bg-zinc-900/50 p-3 space-y-3">
            <label className="flex items-center gap-2 cursor-pointer text-sm font-medium text-slate-800 dark:text-slate-200">
              <input
                type="checkbox"
                checked={scheduleOn}
                onChange={(e) => setScheduleOn(e.target.checked)}
                className="rounded border-slate-300"
              />
              {t('scheduleLabel')}
            </label>
            {scheduleOn ? (
              <input
                type="datetime-local"
                value={scheduleLocal}
                onChange={(e) => setScheduleLocal(e.target.value)}
                className="w-full min-h-[44px] px-3 py-2 rounded-xl border border-slate-200 dark:border-zinc-700 bg-white dark:bg-zinc-950 text-sm"
              />
            ) : null}
            <p className="text-[11px] text-slate-500 dark:text-slate-400 leading-relaxed">
              {t('scheduleHint')}
            </p>
          </div>
        </div>

        <div className="shrink-0 flex flex-col-reverse sm:flex-row gap-2 p-4 border-t border-slate-200 dark:border-zinc-800">
          <button
            type="button"
            onClick={onClose}
            className="flex-1 min-h-[44px] rounded-xl border border-slate-200 dark:border-zinc-700 text-sm font-semibold text-slate-700 dark:text-slate-200"
          >
            {t('cancel')}
          </button>
          <button
            type="button"
            disabled={submitBusy || draft.trim().length < 1}
            onClick={() => void submit()}
            className="flex-1 min-h-[44px] rounded-xl bg-[#25D366] text-white text-sm font-semibold hover:opacity-95 disabled:opacity-50 inline-flex items-center justify-center gap-2"
          >
            {submitBusy ? <Loader2 className="w-4 h-4 animate-spin" /> : null}
            {scheduleOn ? t('schedule') : t('sendNow')}
          </button>
        </div>
      </div>
    </div>,
    document.body
  );
}

'use client';

import { useCallback, useEffect, useMemo, useState } from 'react';
import { ChevronLeft, ChevronRight, Loader2, X } from 'lucide-react';
import { useLocale, useTranslations } from 'next-intl';
import type { PilotageDailyActivityRow, PilotageWeekSummaryRow } from '@/lib/banano/pilotage/types';
import { siteLocaleToIntlDateTag } from '@/lib/i18n/site-locales-catalog';

const TABLE_PAGE = 10;

type Props = { open: boolean; onClose: () => void };

function ymNow(): string {
  const d = new Date();
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
}

function subMonthYm(ym: string, delta: number): string {
  const [y, m] = ym.split('-').map(Number);
  const d = new Date(y, m - 1 + delta, 1);
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
}

export function PilotageDailyCashExplorer({ open, onClose }: Props) {
  const t = useTranslations('Dashboard.bananoPilotageDaily');
  const locale = useLocale();
  const intlTag = siteLocaleToIntlDateTag(locale);
  const fmtEur = useCallback(
    (cents: number) =>
      new Intl.NumberFormat(intlTag, {
        style: 'currency',
        currency: 'EUR',
        maximumFractionDigits: cents % 100 === 0 ? 0 : 2,
      }).format(cents / 100),
    [intlTag]
  );
  const [granularity, setGranularity] = useState<'day' | 'week'>('day');
  const [monthYm, setMonthYm] = useState(ymNow);
  const [customFrom, setCustomFrom] = useState('');
  const [customTo, setCustomTo] = useState('');
  const [useCustom, setUseCustom] = useState(false);
  const [loading, setLoading] = useState(false);
  const [err, setErr] = useState<string | null>(null);
  const [periodLabel, setPeriodLabel] = useState('');
  const [daily, setDaily] = useState<PilotageDailyActivityRow[]>([]);
  const [weekly, setWeekly] = useState<PilotageWeekSummaryRow[]>([]);
  const [page, setPage] = useState(0);

  const monthOptions = useMemo(() => {
    const out: { value: string; label: string }[] = [];
    let ym = ymNow();
    for (let i = 0; i < 36; i++) {
      const [y, m] = ym.split('-').map(Number);
      const d = new Date(y, m - 1, 1);
      out.push({
        value: ym,
        label: d.toLocaleDateString(intlTag, { month: 'long', year: 'numeric' }),
      });
      ym = subMonthYm(ym, -1);
    }
    return out;
  }, [intlTag]);

  const load = useCallback(async () => {
    if (!open) return;
    setLoading(true);
    setErr(null);
    setPage(0);
    try {
      const qs = new URLSearchParams();
      if (useCustom && customFrom && customTo) {
        qs.set('from', customFrom);
        qs.set('to', customTo);
      } else {
        qs.set('month', monthYm);
      }
      qs.set('granularity', granularity);
      qs.set('locale', locale);
      const r = await fetch(`/api/banano/pilotage/daily-activity?${qs}`);
      const j = (await r.json()) as {
        error?: string;
        periodLabel?: string;
        periodLabelFr?: string;
        daily?: PilotageDailyActivityRow[];
        weekly?: PilotageWeekSummaryRow[];
      };
      if (!r.ok) throw new Error(j.error ?? t('errGeneric'));
      setPeriodLabel(j.periodLabel ?? j.periodLabelFr ?? '');
      setDaily(j.daily ?? []);
      setWeekly(j.weekly ?? []);
    } catch (e) {
      setErr(e instanceof Error ? e.message : t('errGeneric'));
      setDaily([]);
      setWeekly([]);
    } finally {
      setLoading(false);
    }
  }, [open, useCustom, customFrom, customTo, monthYm, granularity, locale, t]);

  useEffect(() => {
    void load();
  }, [load]);

  const flatLen = granularity === 'day' ? daily.length : weekly.length;
  const pageCount = Math.max(1, Math.ceil(flatLen / TABLE_PAGE));
  const sliceStart = page * TABLE_PAGE;
  const sliceDaily = daily.slice(sliceStart, sliceStart + TABLE_PAGE);
  const sliceWeek = weekly.slice(sliceStart, sliceStart + TABLE_PAGE);

  useEffect(() => {
    const last = Math.max(0, pageCount - 1);
    if (page > last) setPage(last);
  }, [page, pageCount]);

  if (!open) return null;

  return (
    <div
      className="fixed inset-0 z-[120] flex items-end sm:items-center justify-center p-0 sm:p-4 bg-black/50 backdrop-blur-[2px]"
      role="dialog"
      aria-modal={true}
      aria-labelledby="pilotage-daily-cash-title"
    >
      <div className="relative w-full sm:max-w-5xl max-h-[min(96vh,900px)] rounded-t-3xl sm:rounded-2xl border border-slate-200 dark:border-zinc-700 bg-white dark:bg-[#09090b] shadow-2xl flex flex-col overflow-hidden">
        <div className="shrink-0 flex items-center justify-between gap-3 px-4 py-3 border-b border-slate-200 dark:border-zinc-800">
          <h2
            id="pilotage-daily-cash-title"
            className="text-sm font-bold text-slate-900 dark:text-slate-50"
          >
            {t('title')}
          </h2>
          <button
            type="button"
            onClick={onClose}
            className="p-2 rounded-xl hover:bg-slate-100 dark:hover:bg-zinc-800"
            aria-label={t('close')}
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        <div className="shrink-0 flex flex-col gap-3 px-4 py-3 border-b border-slate-100 dark:border-zinc-800 bg-slate-50/80 dark:bg-zinc-900/50">
          <p className="text-xs text-slate-600 dark:text-slate-400">
            {t('period')}{' '}
            <span className="font-semibold text-slate-800 dark:text-slate-200">{periodLabel}</span>
          </p>
          <div className="flex flex-wrap gap-2 items-center">
            <button
              type="button"
              onClick={() => {
                setUseCustom(false);
                setMonthYm(ymNow());
              }}
              className="min-h-[36px] px-3 rounded-lg text-xs font-semibold bg-[#2563eb] text-white"
            >
              {t('thisMonth')}
            </button>
            <button
              type="button"
              onClick={() => {
                setUseCustom(false);
                setMonthYm(subMonthYm(ymNow(), -1));
              }}
              className="min-h-[36px] px-3 rounded-lg text-xs font-semibold border border-slate-200 dark:border-zinc-600"
            >
              {t('lastMonth')}
            </button>
            <label className="flex items-center gap-2 text-[11px] font-medium text-slate-600">
              {t('monthLabel')}
              <select
                value={useCustom ? '' : monthYm}
                onChange={(e) => {
                  setUseCustom(false);
                  setMonthYm(e.target.value);
                }}
                disabled={useCustom}
                className="min-h-[36px] px-2 rounded-lg border border-slate-200 dark:border-zinc-700 bg-white dark:bg-zinc-950 text-xs capitalize"
              >
                {monthOptions.map((o) => (
                  <option key={o.value} value={o.value}>
                    {o.label}
                  </option>
                ))}
              </select>
            </label>
            <div className="flex flex-wrap items-center gap-2 text-[11px]">
              <label className="inline-flex items-center gap-1">
                <input
                  type="checkbox"
                  checked={useCustom}
                  onChange={(e) => setUseCustom(e.target.checked)}
                />
                {t('customRange')}
              </label>
              <input
                type="date"
                disabled={!useCustom}
                value={customFrom}
                onChange={(e) => setCustomFrom(e.target.value)}
                className="min-h-[32px] px-2 rounded-lg border border-slate-200 dark:border-zinc-700 text-xs disabled:opacity-40"
              />
              <span className="text-slate-400" aria-hidden>
                {t('dateRangeArrow')}
              </span>
              <input
                type="date"
                disabled={!useCustom}
                value={customTo}
                onChange={(e) => setCustomTo(e.target.value)}
                className="min-h-[32px] px-2 rounded-lg border border-slate-200 dark:border-zinc-700 text-xs disabled:opacity-40"
              />
              <button
                type="button"
                disabled={!useCustom || !customFrom || !customTo}
                onClick={() => void load()}
                className="min-h-[32px] px-3 rounded-lg bg-slate-800 dark:bg-slate-200 text-white dark:text-slate-900 text-xs font-semibold disabled:opacity-40"
              >
                {t('refresh')}
              </button>
            </div>
            <div className="flex rounded-lg border border-slate-200 dark:border-zinc-700 p-0.5 ml-auto">
              <button
                type="button"
                onClick={() => setGranularity('day')}
                className={`px-3 py-1.5 rounded-md text-xs font-semibold ${
                  granularity === 'day'
                    ? 'bg-[#2563eb] text-white'
                    : 'text-slate-600 dark:text-slate-400'
                }`}
              >
                {t('byDay')}
              </button>
              <button
                type="button"
                onClick={() => setGranularity('week')}
                className={`px-3 py-1.5 rounded-md text-xs font-semibold ${
                  granularity === 'week'
                    ? 'bg-[#2563eb] text-white'
                    : 'text-slate-600 dark:text-slate-400'
                }`}
              >
                {t('byWeek')}
              </button>
            </div>
          </div>
        </div>

        <div className="flex-1 min-h-0 overflow-auto p-3 sm:p-4">
          {loading ? (
            <div className="flex items-center justify-center gap-2 py-16 text-slate-500">
              <Loader2 className="w-6 h-6 animate-spin" />
              {t('loading')}
            </div>
          ) : err ? (
            <p className="text-sm text-red-600 dark:text-red-400 py-8 text-center">{err}</p>
          ) : granularity === 'day' ? (
            <div className="overflow-x-auto rounded-xl border border-slate-100 dark:border-zinc-800">
              <table className="w-full text-left text-xs sm:text-sm min-w-[720px]">
                <thead className="bg-slate-50 dark:bg-zinc-900/80 text-[10px] uppercase text-slate-500">
                  <tr>
                    <th className="px-3 py-2 font-semibold">{t('thDay')}</th>
                    <th className="px-3 py-2 font-semibold text-right">{t('thPass')}</th>
                    <th className="px-3 py-2 font-semibold text-right">{t('thCa')}</th>
                    <th className="px-3 py-2 font-semibold text-right">{t('thAvg')}</th>
                    <th className="px-3 py-2 font-semibold text-right">{t('thArt')}</th>
                    <th className="px-3 py-2 font-semibold">{t('thTop')}</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 dark:divide-zinc-800">
                  {sliceDaily.map((row) => (
                    <tr key={row.dateKey}>
                      <td className="px-3 py-2 font-medium text-slate-800 dark:text-slate-200">
                        {row.labelFr}
                      </td>
                      <td className="px-3 py-2 text-right tabular-nums">{row.visitCount}</td>
                      <td className="px-3 py-2 text-right tabular-nums">
                        {row.revenueCents > 0 ? fmtEur(row.revenueCents) : t('emptyCell')}
                      </td>
                      <td className="px-3 py-2 text-right tabular-nums">
                        {row.avgBasketCents != null ? fmtEur(row.avgBasketCents) : t('emptyCell')}
                      </td>
                      <td className="px-3 py-2 text-right tabular-nums">
                        {row.itemsSold != null ? row.itemsSold : '—'}
                      </td>
                      <td className="px-3 py-2 text-[11px] leading-relaxed">
                        {row.topLabels.length > 0
                          ? row.topLabels.map((l, idx) => (
                              <span key={`${row.dateKey}-${l.text}-${idx}`}>
                                {idx > 0 ? t('topLabelSep') : null}
                                {t('topLabelEntry', { label: l.text, count: l.count })}
                              </span>
                            ))
                          : t('emptyCell')}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          ) : (
            <div className="overflow-x-auto rounded-xl border border-slate-100 dark:border-zinc-800">
              <table className="w-full text-left text-xs sm:text-sm min-w-[700px]">
                <thead className="bg-slate-50 dark:bg-zinc-900/80 text-[10px] uppercase text-slate-500">
                  <tr>
                    <th className="px-3 py-2 font-semibold">{t('thWeek')}</th>
                    <th className="px-3 py-2 font-semibold text-right">{t('thPass')}</th>
                    <th className="px-3 py-2 font-semibold text-right">{t('thCa')}</th>
                    <th className="px-3 py-2 font-semibold text-right">{t('thAvg')}</th>
                    <th className="px-3 py-2 font-semibold text-right">{t('thArt')}</th>
                    <th className="px-3 py-2 font-semibold">{t('thTop')}</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 dark:divide-zinc-800">
                  {sliceWeek.map((row) => (
                    <tr key={row.weekKey}>
                      <td className="px-3 py-2 font-medium text-slate-800 dark:text-slate-200">
                        {row.labelFr}
                      </td>
                      <td className="px-3 py-2 text-right tabular-nums">{row.visitCount}</td>
                      <td className="px-3 py-2 text-right tabular-nums">
                        {row.revenueCents > 0 ? fmtEur(row.revenueCents) : t('emptyCell')}
                      </td>
                      <td className="px-3 py-2 text-right tabular-nums">
                        {row.avgBasketCents != null ? fmtEur(row.avgBasketCents) : t('emptyCell')}
                      </td>
                      <td className="px-3 py-2 text-right tabular-nums">
                        {row.itemsSold != null ? row.itemsSold : '—'}
                      </td>
                      <td className="px-3 py-2 text-[11px] leading-relaxed">
                        {row.topLabels.length > 0
                          ? row.topLabels.map((l, idx) => (
                              <span key={`${row.weekKey}-${l.text}-${idx}`}>
                                {idx > 0 ? t('topLabelSep') : null}
                                {t('topLabelEntry', { label: l.text, count: l.count })}
                              </span>
                            ))
                          : t('emptyCell')}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>

        {flatLen > TABLE_PAGE ? (
          <div className="shrink-0 flex items-center justify-between gap-2 px-4 py-3 border-t border-slate-200 dark:border-zinc-800">
            <span className="text-xs text-slate-500 tabular-nums">
              {t('page', { current: page + 1, total: pageCount })}
            </span>
            <div className="flex gap-2">
              <button
                type="button"
                disabled={page <= 0}
                onClick={() => setPage((p) => Math.max(0, p - 1))}
                className="inline-flex items-center gap-1 min-h-[40px] px-3 rounded-lg border border-slate-200 dark:border-zinc-700 disabled:opacity-40"
              >
                <ChevronLeft className="w-4 h-4" />
              </button>
              <button
                type="button"
                disabled={page >= pageCount - 1}
                onClick={() => setPage((p) => Math.min(pageCount - 1, p + 1))}
                className="inline-flex items-center gap-1 min-h-[40px] px-3 rounded-lg border border-slate-200 dark:border-zinc-700 disabled:opacity-40"
              >
                <ChevronRight className="w-4 h-4" />
              </button>
            </div>
          </div>
        ) : null}
      </div>
    </div>
  );
}

'use client';

import { useEffect } from 'react';

type Props = {
  children: React.ReactNode;
};

/**
 * Route `/terminal` : limite le pull-to-refresh du navigateur et garde l’écran allumé (Wake Lock).
 */
export function TerminalMobileShell({ children }: Props) {
  useEffect(() => {
    const html = document.documentElement;
    const body = document.body;
    const prevHtmlOsy = html.style.overscrollBehaviorY;
    const prevBodyOsy = body.style.overscrollBehaviorY;
    html.style.overscrollBehaviorY = 'contain';
    body.style.overscrollBehaviorY = 'contain';

    let sentinel: WakeLockSentinel | null = null;

    async function acquireWakeLock() {
      if (typeof navigator === 'undefined' || !('wakeLock' in navigator)) return;
      try {
        if (sentinel) {
          await sentinel.release().catch(() => {});
          sentinel = null;
        }
        sentinel = await navigator.wakeLock.request('screen');
      } catch {
        /* non supporté, onglet arrière-plan, etc. */
      }
    }

    void acquireWakeLock();

    function onVisibility() {
      if (document.visibilityState === 'visible') void acquireWakeLock();
    }
    document.addEventListener('visibilitychange', onVisibility);

    return () => {
      document.removeEventListener('visibilitychange', onVisibility);
      html.style.overscrollBehaviorY = prevHtmlOsy;
      body.style.overscrollBehaviorY = prevBodyOsy;
      void sentinel?.release().catch(() => {});
    };
  }, []);

  return <>{children}</>;
}

