};

const defaultAnnualBadge = '-20%';

const BILLING_TOGGLE_SPRING = { type: 'spring' as const, stiffness: 500, damping: 35 };

/**
 * Toggle Mensuel / Annuel style Apple/Radix avec animation de glissement.
 * Utilise le contexte BillingCycle si value/onChange ne sont pas fournis.
 */
export function BillingToggle({
  value,
  onChange,
  annualBadge = defaultAnnualBadge,
  monthlyLabel,
  annualLabel,
  className = '',
}: Props) {
  const t = useTranslations('Billing.billingToggle');
  const id = useId();
  const context = useBillingCycleOptional();
  const [localCycle, setLocalCycle] = useState<BillingInterval>('month');
  const isControlled = value !== undefined && onChange !== undefined;
  const isAnnual = isControlled
    ? value === 'year'
    : context
      ? context.isAnnual
      : localCycle === 'year';
  const setAnnual = useCallback(
    (annual: boolean) => {
      const next: BillingInterval = annual ? 'year' : 'month';
      if (isControlled) onChange(next);
      else if (context) context.setBillingCycle(next);
      else setLocalCycle(next);
    },
    [isControlled, onChange, context]
  );

  const displayMonthly = monthlyLabel ?? t('monthly');
  const displayAnnual = annualLabel ?? t('annual');

  return (
    <div
      className={`inline-flex items-center gap-3 ${className}`}
      role="group"
      aria-label={t('groupAriaLabel')}
    >
      <span
        className={`text-sm font-medium transition-colors duration-200 ${
          !isAnnual ? 'text-slate-900 dark:text-slate-100' : 'text-slate-500 dark:text-slate-400'
        }`}
      >
        {displayMonthly}
      </span>
      <button
        id={id}
        type="button"
        role="switch"
        aria-checked={isAnnual}
        aria-label={isAnnual ? t('switchAriaAnnual') : t('switchAriaMonthly')}
        onClick={() => setAnnual(!isAnnual)}
        className="relative w-14 h-8 rounded-full bg-slate-200 dark:bg-slate-700 focus:outline-none focus:ring-2 focus:ring-primary focus:ring-offset-2 dark:focus:ring-offset-slate-900 transition-colors duration-200"
      >
        <motion.span
          className="absolute top-1 left-1 w-6 h-6 rounded-full bg-white dark:bg-slate-100 shadow-md"
          animate={{ x: isAnnual ? 24 : 0 }}
          transition={BILLING_TOGGLE_SPRING}
        />
      </button>
      <span
        className={`text-sm font-medium transition-colors duration-200 ${
          isAnnual ? 'text-slate-900 dark:text-slate-100' : 'text-slate-500 dark:text-slate-400'
        }`}
      >
        {displayAnnual}
      </span>
      <span className="ml-1 px-2.5 py-1 rounded-lg bg-emerald-100 dark:bg-emerald-500/20 text-emerald-700 dark:text-emerald-300 text-xs font-bold whitespace-nowrap">
        {annualBadge}
      </span>
    </div>
  );
}

'use client';

import { useState, useRef, useEffect } from 'react';
import { Link } from '@/i18n/navigation';
import { useLocale, useTranslations } from 'next-intl';
import { X, Send, Sparkles } from 'lucide-react';
import { scrubAiTypography } from '@/lib/ai/human-keyboard-output';

type Message = { role: 'user' | 'assistant'; content: string };

export function Chatbot() {
  const locale = useLocale();
  const t = useTranslations('Chatbot');
  const [open, setOpen] = useState(false);
  const [messages, setMessages] = useState<Message[]>([{ role: 'assistant', content: t('welcome') }]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [streamingContent, setStreamingContent] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setMessages([{ role: 'assistant', content: t('welcome') }]);
  }, [locale, t]);

  const userMessageCount = messages.filter((m) => m.role === 'user').length;

  useEffect(() => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  }, [messages, streamingContent, open]);

  const send = async (textOverride?: string) => {
    const text = (textOverride ?? input.trim()).trim();
    if (!text || loading) return;

    setInput('');
    setMessages((prev) => [...prev, { role: 'user', content: text }]);
    setLoading(true);
    setStreamingContent('');

    const fullMessages: Message[] = [...messages, { role: 'user', content: text }];

    try {
      const res = await fetch('/api/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          messages: fullMessages.map((m) => ({ role: m.role, content: m.content })),
          stream: true,
          userMessageCount: userMessageCount + 1,
          locale,
        }),
      });

      if (!res.ok) {
        const data = await res.json().catch(() => ({}));
        throw new Error(typeof data.error === 'string' ? data.error : t('errorFetch'));
      }

      const reader = res.body?.getReader();
      const decoder = new TextDecoder();
      let full = '';

      if (reader) {
        while (true) {
          const { done, value } = await reader.read();
          if (done) break;
          const chunk = decoder.decode(value, { stream: true });
          full += chunk;
          setStreamingContent(scrubAiTypography(full));
        }
      }

      const assistantText = full ? scrubAiTypography(full) : t('noResponse');
      setMessages((prev) => [...prev, { role: 'assistant', content: assistantText }]);
      setStreamingContent('');
    } catch {
      setMessages((prev) => [...prev, { role: 'assistant', content: t('errorSorry') }]);
    } finally {
      setLoading(false);
    }
  };

  const qr = [t('quickReply0'), t('quickReply1'), t('quickReply2'), t('quickReply3')];

  return (
    <>
      {!open && (
        <button
          type="button"
          onClick={() => setOpen(true)}
          className="fixed bottom-5 right-4 sm:bottom-8 sm:right-6 z-[200] group flex items-center gap-3 rounded-full border border-indigo-400/50 bg-gradient-to-r from-[#0f1729] to-[#151f3a] py-3 pl-4 pr-4 sm:pr-5 shadow-[0_8px_40px_-8px_rgba(99,102,241,0.65),0_0_0_1px_rgba(255,255,255,0.06)] transition-all duration-300 hover:scale-[1.03] hover:shadow-[0_12px_48px_-8px_rgba(99,102,241,0.75)] focus:outline-none focus-visible:ring-2 focus-visible:ring-indigo-400 focus-visible:ring-offset-2 focus-visible:ring-offset-[#0a0f1a] max-w-[calc(100vw-1.5rem)]"
          aria-label={t('openChat')}
          aria-expanded={false}
        >
          <span className="relative flex h-11 w-11 shrink-0 items-center justify-center">
            <span
              className="absolute inset-0 rounded-full bg-indigo-500/35 opacity-75 animate-ping motion-reduce:animate-none"
              style={{ animationDuration: '2.2s' }}
              aria-hidden
            />
            <span className="relative flex h-11 w-11 items-center justify-center rounded-full bg-indigo-500 ring-2 ring-indigo-300/50">
              <Sparkles className="h-5 w-5 text-white" aria-hidden />
            </span>
          </span>
          <span className="hidden min-[400px]:flex flex-col items-start text-left pr-1">
            <span className="text-sm font-bold tracking-tight text-white leading-tight">{t('launcherTitle')}</span>
            <span className="text-[10px] font-medium uppercase tracking-wider text-indigo-200/90">
              {t('launcherSubtitle')}
            </span>
          </span>
        </button>
      )}

      <div
        className={`fixed bottom-5 right-4 sm:bottom-8 sm:right-6 z-[200] flex h-[min(580px,calc(100vh-8rem))] w-[min(100vw-1.5rem,420px)] flex-col overflow-hidden rounded-2xl border border-white/15 bg-[#0c1224] shadow-[0_24px_80px_-12px_rgba(0,0,0,0.55),0_0_0_1px_rgba(99,102,241,0.12)] transition-all duration-300 ${
          open ? 'translate-y-0 opacity-100' : 'pointer-events-none translate-y-6 opacity-0'
        }`}
        aria-hidden={!open}
        role="dialog"
        aria-modal={open ? true : undefined}
        aria-label={t('dialogLabel')}
      >
        <div className="flex items-center gap-3 border-b border-white/10 bg-gradient-to-r from-indigo-600/25 to-transparent px-4 py-3.5">
          <div className="flex min-w-0 flex-1 items-center gap-3">
            <div className="flex h-11 w-11 shrink-0 items-center justify-center rounded-xl bg-indigo-500/30 ring-1 ring-indigo-400/40">
              <Sparkles className="h-5 w-5 text-indigo-200" aria-hidden />
            </div>
            <div className="min-w-0">
              <p className="font-bold text-white text-sm tracking-tight">{t('brandName')}</p>
              <p className="text-xs text-indigo-200/95">{t('headerSubtitle')}</p>
            </div>
          </div>
          <button
            type="button"
            onClick={() => setOpen(false)}
            className="flex h-10 w-10 shrink-0 items-center justify-center rounded-xl text-zinc-400 transition hover:bg-white/[0.08] hover:text-white focus:outline-none focus-visible:ring-2 focus-visible:ring-indigo-400 focus-visible:ring-offset-2 focus-visible:ring-offset-[#0c1224]"
            aria-label={t('closeChat')}
          >
            <X className="h-5 w-5" aria-hidden />
          </button>
        </div>

        <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4">
          {messages.map((m, i) => (
            <div
              key={i}
              className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}
            >
              <div
                className={`max-w-[88%] rounded-2xl px-4 py-2.5 ${
                  m.role === 'user'
                    ? 'bg-indigo-600/40 text-white border border-indigo-400/25'
                    : 'bg-white/[0.07] text-zinc-100 border border-white/10'
                }`}
              >
                <p className="text-sm whitespace-pre-wrap leading-relaxed">{m.content}</p>
              </div>
            </div>
          ))}
          {loading && (
            <div className="flex justify-start">
              {streamingContent ? (
                <div className="max-w-[88%] rounded-2xl bg-white/[0.07] border border-white/10 px-4 py-2.5">
                  <p className="text-sm text-zinc-100 whitespace-pre-wrap leading-relaxed">{streamingContent}</p>
                </div>
              ) : (
                <div className="rounded-2xl bg-white/[0.07] border border-white/10 px-4 py-2.5">
                  <span className="inline-flex items-center gap-1 text-sm text-zinc-400">
                    {t('thinking')}
                    <span className="inline-flex gap-0.5">
                      <span className="chat-typing-dot" style={{ animationDelay: '0ms' }}>.</span>
                      <span className="chat-typing-dot" style={{ animationDelay: '0.2s' }}>.</span>
                      <span className="chat-typing-dot" style={{ animationDelay: '0.4s' }}>.</span>
                    </span>
                  </span>
                </div>
              )}
            </div>
          )}
        </div>

        <div className="border-t border-white/10 bg-white/[0.04] px-4 py-2 flex flex-col gap-2">
          <div className="flex flex-wrap gap-1.5">
            {qr.map((q) => (
              <button
                key={q}
                type="button"
                onClick={() => send(q)}
                disabled={loading}
                className="rounded-full bg-white/[0.08] hover:bg-white/[0.14] border border-white/12 px-3 py-1.5 text-[11px] sm:text-xs text-zinc-200 transition-colors disabled:opacity-50 disabled:cursor-not-allowed text-left max-w-full"
              >
                {q}
              </button>
            ))}
          </div>
          <Link
            href="/signup?mode=trial"
            className="flex items-center justify-center gap-2 rounded-xl py-2.5 text-xs font-semibold text-white bg-indigo-600/50 hover:bg-indigo-600/65 border border-indigo-400/35 transition-all"
          >
            {t('trialCta')}
          </Link>
        </div>

        <div className="border-t border-white/10 p-3 bg-black/20">
          <form
            onSubmit={(e) => {
              e.preventDefault();
              send();
            }}
            className="flex gap-2"
          >
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              placeholder={t('placeholder')}
              className="flex-1 rounded-xl border border-white/12 bg-white/[0.08] px-4 py-2.5 text-sm text-white placeholder-zinc-500 focus:border-indigo-500/50 focus:outline-none focus:ring-1 focus:ring-indigo-500/50"
              disabled={loading}
            />
            <button
              type="submit"
              disabled={loading || !input.trim()}
              className="rounded-xl bg-indigo-600 px-4 py-2.5 text-white transition hover:bg-indigo-500 disabled:opacity-50 shrink-0"
              aria-label={t('send')}
            >
              <Send className="h-4 w-4" />
            </button>
          </form>
        </div>
      </div>
    </>
  );
}

'use client';

import { useCallback, useEffect, useId, useMemo, useRef, useState } from 'react';
import { useTranslations, useLocale, useFormatter } from 'next-intl';
import { Link, usePathname } from '@/i18n/navigation';
import { motion, AnimatePresence, type Transition } from 'framer-motion';
import { Check, ChevronDown, ChevronUp, X } from 'lucide-react';
import { isUkGeoCountry, readGeoCountryFromDocumentCookie } from '@/lib/i18n/reputexa-geo-country';
import { formatLegalEffectiveDate } from '@/lib/i18n/format-legal-date';
import { isPublicSitePathname } from '@/lib/compliance/public-site-routes';

const ANON_KEY = 'reputexa_consent_uid';

const COOKIE_BANNER_SPRING: Transition = { type: 'spring', damping: 32, stiffness: 380 };
const MOTION_HEIGHT_AUTO = 'auto' as const;

function getOrCreateAnonId(): string {
  try {
    const exist = localStorage.getItem(ANON_KEY);
    if (exist && exist.length > 8) return exist;
    const id =
      typeof crypto !== 'undefined' && crypto.randomUUID
        ? crypto.randomUUID()
        : `anon-${Date.now()}-${Math.random().toString(36).slice(2)}`;
    localStorage.setItem(ANON_KEY, id);
    return id;
  } catch {
    return `anon-${Date.now()}`;
  }
}

declare global {
  interface Window {
    __REPUTEXA_COOKIE_CONSENT__?: {
      status: string;
      marketing: boolean;
      analytics: boolean;
    };
  }
}

function AppleSwitch({
  checked,
  disabled,
  onToggle,
  id,
  labelledBy,
}: {
  checked: boolean;
  disabled?: boolean;
  onToggle: () => void;
  id: string;
  labelledBy?: string;
}) {
  return (
    <button
      type="button"
      id={id}
      role="switch"
      aria-checked={checked}
      aria-labelledby={labelledBy}
      disabled={disabled}
      onClick={() => {
        if (!disabled) onToggle();
      }}
      className={`relative inline-flex h-8 w-[3.25rem] shrink-0 items-center rounded-full p-1 transition-all focus:outline-none focus-visible:ring-2 focus-visible:ring-blue-500 focus-visible:ring-offset-2 dark:focus-visible:ring-offset-zinc-900 ${
        disabled ? 'cursor-not-allowed opacity-55' : 'cursor-pointer'
      } ${checked ? 'bg-[#34c759]' : 'bg-zinc-400 dark:bg-zinc-600'}`}
    >
      <span
        className={`pointer-events-none block h-6 w-6 shrink-0 rounded-full bg-white shadow-md ring-1 ring-black/[0.06] transition-transform duration-200 ease-out will-change-transform ${
          checked ? 'translate-x-[1.25rem]' : 'translate-x-0'
        }`}
        aria-hidden
      />
    </button>
  );
}

const SCAN_AT_UTC: Intl.DateTimeFormatOptions = {
  dateStyle: 'medium',
  timeStyle: 'short',
  timeZone: 'UTC',
};

export function SiteCookieBanner() {
  const pathname = usePathname();
  const locale = useLocale();
  const format = useFormatter();
  const tEu = useTranslations('Compliance.cookieBanner');
  const tUk = useTranslations('Compliance.cookieBannerUk');
  const [ukVisitor] = useState(() => isUkGeoCountry(readGeoCountryFromDocumentCookie()));
  const t = useMemo(() => (ukVisitor ? tUk : tEu), [ukVisitor, tEu, tUk]);

  const titleId = useId();
  const descId = useId();
  const essLabel = useId();
  const anLabel = useId();
  const mkLabel = useId();

  const [visible, setVisible] = useState(false);
  const [busy, setBusy] = useState(false);
  const [anonId, setAnonId] = useState<string | null>(null);
  const [analyticsOn, setAnalyticsOn] = useState(false);
  const [marketingOn, setMarketingOn] = useState(false);
  const [legalEffectiveDate, setLegalEffectiveDate] = useState<string | null>(null);
  const [cookieInventoryHint, setCookieInventoryHint] = useState<string | null>(null);
  const [guardianLastRunAt, setGuardianLastRunAt] = useState<string | null>(null);
  const [detailsOpen, setDetailsOpen] = useState(false);
  const [serverGpc, setServerGpc] = useState(false);
  const [consentVersionGate, setConsentVersionGate] = useState(0);
  const gpcStorageFallbackLock = useRef(false);

  const showOnThisRoute =
    isPublicSitePathname(pathname) ||
    (typeof window !== 'undefined' && isPublicSitePathname(window.location.pathname));

  const browserGpc = typeof navigator !== 'undefined' && navigator.globalPrivacyControl === true;
  const showGpcLine = serverGpc || browserGpc;

  const refresh = useCallback(async () => {
    let aid: string | null = null;
    try {
      aid = getOrCreateAnonId();
      setAnonId(aid);
    } catch {
      aid = null;
    }
    const params = new URLSearchParams();
    if (aid) params.set('anonymous_id', aid);
    params.set('ui_locale', locale);
    try {
      const res = await fetch(`/api/consent/site?${params.toString()}`, { credentials: 'include' });
      if (!res.ok) {
        setVisible(true);
        setAnalyticsOn(false);
        setMarketingOn(false);
        return;
      }
      let data: {
        needsBanner?: boolean;
        currentLegalVersion?: number;
        legalEffectiveDate?: string | null;
        cookieInventoryHint?: string | null;
        guardianLastRunAt?: string | null;
        toggleDefaults?: { analytics?: boolean; marketing?: boolean };
        globalPrivacyControl?: boolean;
      };
      try {
        data = (await res.json()) as typeof data;
      } catch {
        setVisible(true);
        return;
      }
      setServerGpc(data.globalPrivacyControl === true);
      setConsentVersionGate(
        typeof data.currentLegalVersion === 'number' && Number.isFinite(data.currentLegalVersion)
          ? data.currentLegalVersion
          : 0
      );
      setVisible(!!data.needsBanner);
      const td = data.toggleDefaults;
      if (td && typeof td === 'object') {
        setAnalyticsOn(!!td.analytics);
        setMarketingOn(!!td.marketing);
      } else {
        setAnalyticsOn(false);
        setMarketingOn(false);
      }
      setLegalEffectiveDate(
        typeof data.legalEffectiveDate === 'string' && data.legalEffectiveDate ? data.legalEffectiveDate : null
      );
      setCookieInventoryHint(
        typeof data.cookieInventoryHint === 'string' && data.cookieInventoryHint.trim()
          ? data.cookieInventoryHint.trim()
          : null
      );
      setGuardianLastRunAt(
        typeof data.guardianLastRunAt === 'string' && data.guardianLastRunAt.trim()
          ? data.guardianLastRunAt.trim()
          : null
      );
    } catch {
      setVisible(true);
    }
  }, [locale]);

  useEffect(() => {
    if (!showOnThisRoute) {
      setVisible(false);
      return;
    }
    void refresh();
  }, [refresh, showOnThisRoute, pathname]);

  const persistChoice = useCallback(async (nextA: boolean, nextM: boolean): Promise<boolean> => {
    setBusy(true);
    try {
      const id = anonId ?? getOrCreateAnonId();
      setAnonId(id);
      const navigatorLanguage = typeof navigator !== 'undefined' ? navigator.language : '';
      const gpcObserved = typeof navigator !== 'undefined' && navigator.globalPrivacyControl === true;
      const res = await fetch('/api/consent/site', {
        method: 'POST',
        credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          anonymous_id: id,
          ui_locale: locale,
          navigator_language: navigatorLanguage,
          analytics_opt_in: nextA,
          marketing_opt_in: nextM,
          gpc_signal_observed: gpcObserved,
        }),
      });
      if (res.ok) {
        const st = nextA && nextM ? 'all' : !nextA && !nextM ? 'necessary' : 'partial';
        window.__REPUTEXA_COOKIE_CONSENT__ = {
          status: st,
          marketing: nextM,
          analytics: nextA,
        };
        setVisible(false);
        setDetailsOpen(false);
        return true;
      }
      return false;
    } finally {
      setBusy(false);
    }
  }, [anonId, locale]);

  useEffect(() => {
    if (!showOnThisRoute || !visible || busy) return;
    const navGpc = typeof navigator !== 'undefined' && navigator.globalPrivacyControl === true;
    if (!serverGpc && !navGpc) return;
    const storageKey = `reputexa_gpc_autosync:v${consentVersionGate}`;
    let lockedSession = false;
    try {
      const cur = sessionStorage.getItem(storageKey);
      if (cur === '1' || cur === 'pending') return;
      sessionStorage.setItem(storageKey, 'pending');
      lockedSession = true;
    } catch {
      if (gpcStorageFallbackLock.current) return;
      gpcStorageFallbackLock.current = true;
    }
    setAnalyticsOn(false);
    setMarketingOn(false);
    void (async () => {
      const ok = await persistChoice(false, false);
      if (lockedSession) {
        try {
          if (ok) sessionStorage.setItem(storageKey, '1');
          else sessionStorage.removeItem(storageKey);
        } catch {
          /* ignore */
        }
      } else if (!ok) {
        gpcStorageFallbackLock.current = false;
      }
    })();
  }, [showOnThisRoute, visible, serverGpc, busy, persistChoice, consentVersionGate]);

  function saveCurrentToggles() {
    void persistChoice(analyticsOn, marketingOn);
  }

  function acceptAllQuick() {
    setAnalyticsOn(true);
    setMarketingOn(true);
    void persistChoice(true, true);
  }

  function rejectOptionalQuick() {
    setAnalyticsOn(false);
    setMarketingOn(false);
    void persistChoice(false, false);
  }

  const updatedLine =
    legalEffectiveDate &&
    t('legalUpdatedLine', { date: formatLegalEffectiveDate(legalEffectiveDate, locale) });

  const scanLine =
    guardianLastRunAt &&
    (() => {
      try {
        return t('scanSyncedLine', {
          datetime: format.dateTime(new Date(guardianLastRunAt), SCAN_AT_UTC),
        });
      } catch {
        return t('scanSyncedLine', { datetime: guardianLastRunAt });
      }
    })();

  const cat = {
    essentialTitle: t('catEssentialTitle'),
    essentialDesc: t('catEssentialDesc'),
    analyticsTitle: t('catAnalyticsTitle'),
    analyticsDesc: t('catAnalyticsDesc'),
    marketingTitle: t('catMarketingTitle'),
    marketingDesc: t('catMarketingDesc'),
    saveChoices: t('saveChoices'),
    quickAccept: t('quickAccept'),
    quickReject: t('quickReject'),
  };

  return (
    <AnimatePresence>
      {showOnThisRoute && visible ? (
        <motion.div
          role="dialog"
          aria-modal="true"
          aria-labelledby={titleId}
          aria-describedby={detailsOpen ? descId : undefined}
          initial={{ y: 20, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          exit={{ y: 12, opacity: 0 }}
          transition={COOKIE_BANNER_SPRING}
          className="fixed bottom-0 left-0 right-0 z-[9999] print:hidden border-t border-zinc-300 bg-zinc-100/95 px-2 pb-2 pt-1 dark:border-zinc-700 dark:bg-zinc-950"
        >
          <div className="mx-auto max-w-lg sm:max-w-xl rounded-t-2xl border border-zinc-200 bg-white px-4 py-3.5 text-zinc-900 shadow-xl shadow-zinc-900/10 dark:border-zinc-700 dark:bg-zinc-900 dark:text-zinc-50 sm:px-5 sm:py-4">
            <div className="flex items-start justify-between gap-3">
              <div className="min-w-0">
                <p id={titleId} className="text-[15px] font-semibold leading-snug tracking-tight text-zinc-950 dark:text-white">
                  {t('title')}
                </p>
