          <a
            href={`/${locale}/pricing`}
            className="inline-flex shrink-0 items-center gap-1.5 text-sm font-semibold text-sky-600 dark:text-sky-400 hover:underline"
          >
            <ArrowRight className="w-4 h-4" />
            {t('comparePlans')}
