  const styles = PLAN_STYLES[planSlug];

  const futurePlanName = selectedPlanFromProfile
    ? FUTURE_PLAN_DISPLAY[selectedPlanFromProfile.toLowerCase()] ?? selectedPlanFromProfile.toUpperCase()
    : null;
  const showFuturePlanLine = isTrialing && !!futurePlanName;

  const label = isTrialing
    ? trialDaysLeft != null
      ? t('trialWithDays', { planName: planDisplayName, days: trialDaysLeft })
      : t('trialSimple', { planName: planDisplayName })
    : planDisplayName;

  const isUrgent = isTrialing && trialDaysLeft != null && trialDaysLeft < 3;
  const labelColorClass = isUrgent
    ? trialDaysLeft === 0
      ? 'text-red-300'
      : 'text-amber-300'
    : 'text-white';

  const handleClick = async () => {
    setLoading(true);
    try {
      const portalUrl = await openStripePortal(locale, t('toastPortalOpenFailed'));
      if (portalUrl) window.location.href = portalUrl;
      else toast.error(t('toastPortalOpenFailed'));
    } catch (err) {
      toast.error(err instanceof Error ? err.message : t('toastGenericError'));
    } finally {
      setLoading(false);
    }
  };

  return (
    <div
      className={`m-3 p-4 rounded-xl bg-gradient-to-br ${styles.bg} border ${styles.border} ${styles.glow ?? ''} flex flex-col gap-2 min-w-0`}
    >
      <div className="flex items-start gap-2 min-w-0">
        <div className={`w-8 h-8 shrink-0 rounded-lg flex items-center justify-center bg-white/10 ${styles.icon}`}>
          <Icon className="h-4 w-4 flex-shrink-0" />
        </div>
        <span className={`text-xs font-semibold min-w-0 flex-1 break-words ${labelColorClass}`}>
          {label}
        </span>
      </div>
      {showFuturePlanLine && (
        <p className="text-xs opacity-80 text-white/80 flex items-start gap-1.5 mt-0.5 min-w-0">
          <Calendar className="h-3.5 w-3.5 flex-shrink-0 mt-0.5" aria-hidden />
          <span className="min-w-0 break-words">
            {t('futureScheduled', { plan: futurePlanName ?? '' })}
          </span>
        </p>
      )}
      {!isTrialing && (
        <button
          type="button"
          onClick={handleClick}
          disabled={loading}
          className="w-full min-w-0 py-2 px-2 text-xs font-medium rounded-lg bg-white/10 hover:bg-white/5 dark:hover:bg-white/5 text-white/90 transition-colors disabled:opacity-60 flex items-center justify-center gap-1.5 text-center"
        >
          {loading ? <Loader2 className="w-3.5 h-3.5 shrink-0 animate-spin" /> : null}
          <span className="break-words">
            {hasActiveSubscription ? t('ctaChangePlan') : t('ctaUpgrade')}
          </span>
        </button>
      )}
    </div>
  );
}

'use client';

import { useTranslations } from 'next-intl';
import { useMemo, useState, useEffect } from 'react';
import {
  ResponsiveContainer,
  PieChart,
  Pie,
  Cell,
  Tooltip as RechartsTooltip,
} from 'recharts';

type PlatformDistributionChartProps = {
  reviews: { source: string }[];
};

type PlatformKey = 'Google' | 'Facebook' | 'Trustpilot' | 'Other';

type PieDatum = {
  name: PlatformKey;
  value: number;
  percentage: number;
};

const COLORS: Record<PlatformKey, string> = {
  Google: '#2563eb',
  Facebook: '#1877F2',
  Trustpilot: '#00B67A',
  Other: '#cbd5f5',
};

function mapSourceToPlatform(sourceRaw: string | null | undefined): PlatformKey {
  const s = String(sourceRaw ?? '').toLowerCase();
  if (s.includes('google')) return 'Google';
  if (s.includes('facebook')) return 'Facebook';
  if (s.includes('trustpilot')) return 'Trustpilot';
  if (!s || s === 'null' || s === 'undefined') return 'Other';
  return 'Other';
}

function CustomTooltip({
  active,
  payload,
  percentLabel,
}: {
  active?: boolean;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  payload?: any[];
  percentLabel: string;
}) {
  if (!active || !payload || !payload.length) return null;
  const datum = payload[0].payload as PieDatum;
  return (
    <div className="rounded-xl border border-slate-200 bg-white px-3 py-2 text-xs shadow-lg">
      <div className="font-semibold text-slate-900 flex items-center gap-1">
        <span
          className="inline-block h-2 w-2 rounded-full"
          style={{ backgroundColor: COLORS[datum.name] }}
        />
        {datum.name}
      </div>
      <div className="mt-1 text-slate-600">
        {datum.percentage.toFixed(0)}
        {percentLabel}
      </div>
    </div>
  );
}

export function PlatformDistributionChart({ reviews }: PlatformDistributionChartProps) {
  const t = useTranslations('PlatformChart');
  const [isMounted, setIsMounted] = useState(false);

  useEffect(() => {
    setIsMounted(true);
  }, []);

  const data: PieDatum[] = useMemo(() => {
    if (!reviews.length) {
      return [
        { name: 'Other', value: 1, percentage: 100 },
      ];
    }

    const counts: Record<PlatformKey, number> = {
      Google: 0,
      Facebook: 0,
      Trustpilot: 0,
      Other: 0,
    };

    reviews.forEach((r) => {
      const p = mapSourceToPlatform(r.source);
      counts[p] += 1;
    });

    const total = Object.values(counts).reduce((s, v) => s + v, 0) || 1;

    return (Object.keys(counts) as PlatformKey[])
      .filter((k) => counts[k] > 0)
      .map((k) => ({
        name: k,
        value: counts[k],
        percentage: (counts[k] / total) * 100,
      }));
  }, [reviews]);

  if (!isMounted) return null;
  const hasData = reviews.length > 0;

  return (
    <div className="flex items-center gap-5">
      <div className="w-32 h-32">
        <ResponsiveContainer width="100%" height="100%">
          <PieChart>
            <RechartsTooltip content={<CustomTooltip percentLabel={t('percentOfReviews')} />} />
            <Pie
              data={data}
              dataKey="value"
              nameKey="name"
              innerRadius="80%"
              outerRadius="90%"
              paddingAngle={2}
              stroke="none"
              isAnimationActive
            >
              {data.map((entry) => (
                <Cell
                  key={entry.name}
                  fill={COLORS[entry.name]}
                  className="transition-all duration-200 origin-center hover:scale-105"
                />
              ))}
            </Pie>
          </PieChart>
        </ResponsiveContainer>
      </div>
      <div className="flex-1 space-y-2.5">
        {hasData ? (
          data.map((d) => (
            <div key={d.name} className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <span
                  className="w-2.5 h-2.5 rounded-full"
                  style={{ backgroundColor: COLORS[d.name] }}
                />
                <span className="text-xs font-medium text-slate-700 dark:text-slate-300">
                  {d.name}
                </span>
              </div>
              <span className="text-xs font-bold text-slate-900 dark:text-slate-100">
                {d.percentage.toFixed(0)}%
              </span>
            </div>
          ))
        ) : (
          <p className="text-[11px] text-slate-400">
            {t('emptyHint')}
          </p>
        )}
      </div>
    </div>
  );
}

'use client';

import { useMemo, useState, useId } from 'react';
import { useTheme } from 'next-themes';
import {
  ResponsiveContainer,
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip as RechartsTooltip,
} from 'recharts';
import { useTranslations } from 'next-intl';
import { subDays, startOfDay } from 'date-fns';
import { formatInTimeZone, toZonedTime, fromZonedTime } from 'date-fns-tz';
import { fr, enUS, es, de, it } from 'date-fns/locale';

const RATING_CHART_PRIMARY = '#2563eb';

type ReviewItem = {
  rating: number;
  createdAt: string;
};

type RatingEvolutionChartProps = {
  reviews: ReviewItem[];
  locale: string;
  /** IANA — calendrier / libellés alignés sur l’établissement. */
  timeZone: string;
};

const dateLocaleMap = { fr, en: enUS, es, de, it, pt: enUS, ja: enUS, zh: enUS } as const;

export function RatingEvolutionChart({ reviews, locale, timeZone }: RatingEvolutionChartProps) {
  const t = useTranslations('Statistics');
  const { resolvedTheme } = useTheme();
  const [period, setPeriod] = useState<7 | 14 | 30 | 90>(90);
  const gradientId = `rating-grad-${useId().replace(/:/g, '')}`;
  const isDark = resolvedTheme === 'dark';
  const gridStroke = isDark ? 'rgba(148,163,184,0.18)' : 'rgb(226 232 240)';
  const tickFill = isDark ? 'rgb(148 163 184)' : 'rgb(100 116 139)';

  const localeObj = dateLocaleMap[locale as keyof typeof dateLocaleMap] ?? enUS;

  const evolutionChartData = useMemo(() => {
    const now = new Date();
    const zNow = toZonedTime(now, timeZone);
    const startToday = startOfDay(zNow);
    const days: { label: string; rating: number }[] = [];
    for (let i = period - 1; i >= 0; i--) {
      const dayLocal = subDays(startToday, i);
      const instant = fromZonedTime(dayLocal, timeZone);
      const ymd = formatInTimeZone(instant, timeZone, 'yyyy-MM-dd');
      const dayReviews = reviews.filter((r) => {
        const created = new Date(r.createdAt);
        if (Number.isNaN(created.getTime())) return false;
        if (r.rating < 1 || r.rating > 5) return false;
        return formatInTimeZone(created, timeZone, 'yyyy-MM-dd') === ymd;
      });
      const avg =
        dayReviews.length > 0
          ? dayReviews.reduce((s, r) => s + r.rating, 0) / dayReviews.length
          : 0;
      const label = formatInTimeZone(
        instant,
        timeZone,
        period === 7 ? 'EEE' : 'd MMM',
        { locale: localeObj }
      );
      days.push({ label, rating: avg });
    }
    let last = 0;
    return days.map((item) => {
      const r = item.rating > 0 ? item.rating : last;
      if (item.rating > 0) last = item.rating;
      return { ...item, rating: r };
    });
  }, [reviews, period, localeObj, timeZone]);

  return (
    <div className="min-w-0 w-full">
      <div className="flex items-center justify-between gap-3 mb-3 flex-wrap">
        <h2 className="font-display font-semibold text-slate-800 dark:text-slate-100 text-sm">
          {t('ratingEvolution')}
        </h2>
        <div className="flex gap-1">
          {([7, 14, 30, 90] as const).map((p) => (
            <button
              key={p}
              type="button"
              onClick={() => setPeriod(p)}
              className={`rounded-lg px-2.5 py-1 text-xs font-medium transition-colors ${
                period === p
                  ? 'bg-[#2563eb] text-white'
                  : 'bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-700'
              }`}
            >
              {t(`period${p}d`)}
            </button>
          ))}
        </div>
      </div>
      <div className="h-52 min-h-[200px] w-full" style={{ minWidth: 0 }}>
        <ResponsiveContainer width="100%" height="100%">
          <AreaChart data={evolutionChartData} margin={{ top: 8, right: 8, bottom: 8, left: 0 }}>
            <defs>
              <linearGradient id={gradientId} x1="0" y1="0" x2="0" y2="1">
                <stop offset="0%" stopColor="#2563eb" stopOpacity={0.4} />
                <stop offset="100%" stopColor="#2563eb" stopOpacity={0} />
              </linearGradient>
            </defs>
            <CartesianGrid strokeDasharray="3 3" stroke={gridStroke} horizontal vertical={false} />
            <XAxis dataKey="label" tickLine={false} axisLine={false} tick={{ fill: tickFill, fontSize: 11 }} />
            <YAxis domain={[0, 5]} ticks={[0, 1, 2, 3, 4, 5]} tickLine={false} axisLine={false} tick={{ fill: tickFill, fontSize: 11 }} width={24} />
            <RechartsTooltip
              formatter={(value, _n, props) => {
                const label = (props?.payload as { label?: string })?.label ?? '';
                return [
                  t('ratingTooltipLine', {
                    label,
                    rating: Number(value ?? 0).toFixed(2),
                  }),
                  '',
                ];
              }}
            />
            <Area
              type="monotone"
              dataKey="rating"
              stroke={RATING_CHART_PRIMARY}
              strokeWidth={2}
              fill={`url(#${gradientId})`}
              dot={false}
              activeDot={{ r: 4, fill: RATING_CHART_PRIMARY, strokeWidth: 0 }}
              connectNulls
            />
          </AreaChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
}

