              )}
              {ticketsOpen.map((tk) => {
                const fallback = t('ticketTitle', { date: formatShort(tk.updated_at, locale) });
                const isActive = activeId === tk.id;
                const isRenaming = renamingId === tk.id;
                return (
                  <li key={tk.id}>
