            </button>
          </div>
        ) : (
          <>
            {/* ── Fil de conversation ── */}
            <div
              ref={scrollRef}
              className="flex-1 overflow-y-auto px-4 sm:px-6 py-5 space-y-5 min-h-0 scrollbar-thin scrollbar-thumb-slate-200 dark:scrollbar-thumb-zinc-700"
            >
              {loadingChat ? (
                <div className="flex justify-center py-16">
                  <Loader2 className="w-6 h-6 animate-spin text-indigo-400" />
                </div>
              ) : messages.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-full gap-4 py-12 text-center">
                  <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-indigo-100 to-violet-100 dark:from-indigo-950/40 dark:to-violet-950/40 flex items-center justify-center">
                    <ShieldCheck className="w-6 h-6 text-indigo-500" />
                  </div>
                  <div>
                    <p className="text-sm font-semibold text-slate-700 dark:text-zinc-200">
                      {t('greetingTitle')}
                    </p>
                    <p className="text-xs text-slate-400 dark:text-zinc-500 mt-1 max-w-xs mx-auto">
                      {t('greetingSubtitle')}
                    </p>
                  </div>
                </div>
              ) : (
                messages.map((m, i) => (
                  <MessageBubble
                    key={m.id ?? `${m.sender}-${i}`}
                    msg={m}
                    locale={locale}
                    agentLabel={t('bubbleAgentLabel')}
                  />
                ))
              )}

              {/* Indicateur de traitement agent */}
              {sending && <AgentThinking />}
            </div>

            {/* ── Zone de saisie ── */}
            {isArchived ? (
              <div className="px-4 py-3 border-t border-slate-100 dark:border-zinc-800/70 text-center text-xs text-slate-400 dark:text-zinc-500 bg-white/60 dark:bg-zinc-900/40">
                {t('readOnlyArchived')}
              </div>
            ) : (
              <form
                className="px-4 sm:px-5 py-3 border-t border-slate-100 dark:border-zinc-800/70 flex gap-2 items-end shrink-0 bg-white/80 dark:bg-zinc-900/60 backdrop-blur-sm"
                onSubmit={(e) => { e.preventDefault(); void sendMessage(); }}
              >
                <textarea
                  ref={inputRef}
                  rows={1}
                  value={input}
                  onChange={handleInputChange}
                  onKeyDown={handleKeyDown}
                  disabled={sending}
                  placeholder={t('placeholder')}
                  className="flex-1 min-w-0 resize-none px-4 py-3 rounded-xl border border-slate-200 dark:border-zinc-700 bg-white dark:bg-zinc-900 text-slate-900 dark:text-zinc-100 placeholder:text-slate-400 focus:outline-none focus:ring-2 focus:ring-indigo-500/40 text-sm leading-relaxed transition-all disabled:opacity-60 max-h-[120px] overflow-y-auto scrollbar-thin"
                  style={{ height: '46px' }}
                />
                <button
                  type="submit"
                  disabled={sending || !input.trim()}
                  className="p-3 rounded-xl bg-indigo-600 hover:bg-indigo-700 active:scale-95 disabled:opacity-40 disabled:cursor-not-allowed text-white transition-all shadow-sm shrink-0"
                  aria-label={t('sendMessageAria')}
                >
                  {sending ? (
                    <Loader2 className="w-4 h-4 animate-spin" />
                  ) : (
                    <Send className="w-4 h-4" />
                  )}
                </button>
              </form>
            )}
          </>
        )}
      </section>

      <SupportVerdictModal
        open={verdictOpen}
        onOpenChange={setVerdictOpen}
        onConfirm={submitArchiveWithVerdict}
        title={t('verdictArchiveTitle')}
        confirmLabel={t('verdictArchiveConfirm')}
      />
    </div>
  );
}

'use client';

import { useEffect, useRef } from 'react';
import { useSearchParams } from 'next/navigation';
import { useActiveLocationOptional } from '@/lib/active-location-context';

/**
 * Quand l'URL contient ?location=xxx ou ?eid=xxx, synchronise l'établissement actif
 * du dashboard avec ce paramètre (cookie + contexte). Permet deep-link et partage d'URL.
 */
export function SyncLocationFromUrl() {
  const searchParams = useSearchParams();
  const activeLocation = useActiveLocationOptional();
  const appliedRef = useRef(false);

  useEffect(() => {
    const loc = searchParams?.get('location') ?? searchParams?.get('eid');
    if (!loc || !activeLocation?.setActiveLocationId || appliedRef.current) return;

    const validIds = activeLocation.locations.map((l) => l.id);
    if (validIds.includes(loc)) {
      activeLocation.setActiveLocationId(loc);
      appliedRef.current = true;
    }
  }, [searchParams, activeLocation]);

  return null;
}

'use client';

import { useState, useCallback, useRef } from 'react';
import Image from 'next/image';
import { useRouter } from 'next/navigation';
import { useLocale, useTranslations } from 'next-intl';
import { Check, ImagePlus, Loader2, Pencil, Trash2, X, Zap } from 'lucide-react';
import { toast } from 'sonner';
import { DeleteConfirmModal } from '@/components/dashboard/delete-confirm-modal';
import {
  normalizeAttachments as normalizeAttachmentsImpl,
  type UpdateAttachment,
} from '@/lib/updates/normalize-attachments';
import { siteLocaleToIntlDateTag } from '@/lib/i18n/site-locales-catalog';

const DELETE_UPDATE_MODAL_TITLE_ID = 'delete-update-title';
const DELETE_UPDATE_MODAL_DESC_ID = 'delete-update-desc';

export type { UpdateAttachment };

export type Update = {
  id: string;
  title: string;
  content?: string | null;
  attachments?: UpdateAttachment[];
  completedAt: string;
  /** ISO — communiqués manuels : instant de visibilité publique (peut être futur pour l’admin). */
  publishAt?: string;
  source: 'suggestion' | 'manual';
};

export function normalizeAttachments(raw: unknown): UpdateAttachment[] {
  return normalizeAttachmentsImpl(raw);
}

export function UpdateAttachmentsMedia({ items }: { items: UpdateAttachment[] }) {
  if (!items.length) return null;
  return (
    <div className="mt-3 flex flex-col gap-3">
      {items.map((a, idx) => (
        <div
          key={`${a.url}-${idx}`}
          className="rounded-xl border border-slate-200/80 dark:border-zinc-700 overflow-hidden bg-slate-50/50 dark:bg-zinc-950/40"
        >
          {a.type === 'image' ? (
            <Image
              src={a.url}
              alt=""
              width={800}
              height={288}
              className="max-h-72 w-full object-contain"
              sizes="(max-width: 768px) 100vw, 800px"
              loading="lazy"
              unoptimized
            />
          ) : (
            <video src={a.url} controls className="max-h-72 w-full" preload="metadata" />
          )}
        </div>
      ))}
    </div>
  );
}

type Props = {
  updates: Update[];
  locale: string;
  /** Affiche Modifier / Supprimer sur les communiqués manuels */
  isAdmin?: boolean;
};

function formatDate(iso: string, locale: string): string {
  return new Date(iso).toLocaleDateString(siteLocaleToIntlDateTag(locale), {
    day: 'numeric',
    month: 'long',
    year: 'numeric',
  });
}

function formatDateTime(iso: string, locale: string): string {
  return new Date(iso).toLocaleString(siteLocaleToIntlDateTag(locale), {
    day: 'numeric',
    month: 'long',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  });
}

export function UpdatesList({ updates, locale, isAdmin = false }: Props) {
  const tu = useTranslations('Dashboard.updatesList');
  const dashboardLocale = useLocale();
  const router = useRouter();
  const editMediaInputRef = useRef<HTMLInputElement | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');
  const [editContent, setEditContent] = useState('');
  const [editAttachments, setEditAttachments] = useState<UpdateAttachment[]>([]);
  const [editMediaUploading, setEditMediaUploading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [deletingId, setDeletingId] = useState<string | null>(null);
  /** Modale de confirmation suppression */
  const [deleteTarget, setDeleteTarget] = useState<{ id: string; title: string } | null>(null);

  const closeDeleteModal = useCallback(() => {
    if (deletingId) return;
    setDeleteTarget(null);
  }, [deletingId]);

  const startEdit = (u: Update) => {
    setEditingId(u.id);
    setEditTitle(u.title);
    setEditContent(u.content ?? '');
    setEditAttachments(normalizeAttachments(u.attachments));
  };

  const cancelEdit = () => {
    setEditingId(null);
    setEditTitle('');
    setEditContent('');
    setEditAttachments([]);
  };

  const uploadEditMedia = async (files: FileList | null) => {
    if (!files?.length) return;
    setEditMediaUploading(true);
    try {
      let next = [...editAttachments];
      for (const file of Array.from(files)) {
        const fd = new FormData();
        fd.append('file', file);
        const res = await fetch('/api/admin/updates/upload', {
          method: 'POST',
          body: fd,
          credentials: 'include',
        });
        const data = await res.json().catch(() => ({}));
        if (!res.ok) throw new Error(data.error ?? tu('errUploadFallback'));
        next = [...next, { url: data.url as string, type: data.type as 'image' | 'video' }];
      }
      setEditAttachments(next);
    } catch (e) {
      toast.error(e instanceof Error ? e.message : tu('toastUploadErr'));
    } finally {
      setEditMediaUploading(false);
      if (editMediaInputRef.current) editMediaInputRef.current.value = '';
    }
  };

  const saveEdit = async (id: string) => {
    const title = editTitle.trim();
    const content = editContent.trim();
    if (!title || !content) {
      toast.error(tu('toastTitleContentRequired'));
      return;
    }
    setSaving(true);
    try {
      const res = await fetch('/api/admin/updates', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          id,
          title,
          content,
          attachments: editAttachments,
          source_locale: dashboardLocale,
        }),
        credentials: 'include',
      });
      const data = await res.json().catch(() => ({}));
      if (!res.ok) throw new Error(data.error ?? tu('errGenericFallback'));
      toast.success(tu('toastSaved'));
      cancelEdit();
      router.refresh();
    } catch (e) {
      toast.error(e instanceof Error ? e.message : tu('toastSaveErr'));
    } finally {
      setSaving(false);
    }
  };

  const confirmDelete = async () => {
    if (!deleteTarget) return;
    const id = deleteTarget.id;
    setDeletingId(id);
    try {
      const res = await fetch(`/api/admin/updates?id=${encodeURIComponent(id)}`, {
        method: 'DELETE',
        credentials: 'include',
      });
      const data = await res.json().catch(() => ({}));
      if (!res.ok) throw new Error(data.error ?? tu('errGenericFallback'));
      toast.success(tu('toastDeleted'));
      setDeleteTarget(null);
      if (editingId === id) cancelEdit();
      router.refresh();
    } catch (e) {
      toast.error(e instanceof Error ? e.message : tu('toastDeleteErr'));
    } finally {
      setDeletingId(null);
    }
  };

  const nowMs = Date.now();

  if (updates.length === 0) {
    return (
      <div className="rounded-2xl border border-slate-200 dark:border-zinc-800/50 bg-white dark:bg-[#09090b] p-8 text-center">
        <p className="text-sm text-slate-500 dark:text-zinc-400">
