'use client';

import { useEffect, useRef, useState } from 'react';
import { usePathname, useSearchParams } from 'next/navigation';
import { useTranslations } from 'next-intl';
import { Logo } from '@/components/logo';

const DELAY_MS = 1000;

function shouldTrackAnchorClick(e: MouseEvent, a: HTMLAnchorElement): boolean {
  if (e.defaultPrevented || e.button !== 0) return false;
  if (e.metaKey || e.ctrlKey || e.shiftKey || e.altKey) return false;
  if (a.target === '_blank' || a.hasAttribute('download')) return false;
  const href = a.getAttribute('href');
  if (!href || href.startsWith('#')) return false;
  if (href.startsWith('mailto:') || href.startsWith('tel:') || href.startsWith('javascript:')) return false;
  try {
    const u = new URL(href, window.location.origin);
    if (u.origin !== window.location.origin) return false;
    if (u.pathname === window.location.pathname && u.search === window.location.search) return false;
  } catch {
    return false;
  }
  return true;
}

/**
 * Shows a branded (spinning logo) overlay only when client navigation takes longer than {@link DELAY_MS}.
 * Relies on link-click + popstate heuristics (App Router does not expose router events).
 */
export function NavigationLoadingOverlay() {
  const pathname = usePathname();
  const searchParams = useSearchParams();
  const t = useTranslations('Common.navigationLoading');
  const [visible, setVisible] = useState(false);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const routeKey = `${pathname ?? ''}?${searchParams?.toString() ?? ''}`;

  useEffect(() => {
    setVisible(false);
    if (timerRef.current) {
      clearTimeout(timerRef.current);
      timerRef.current = null;
    }
  }, [routeKey]);

  useEffect(() => {
    function armTimer() {
      if (timerRef.current) clearTimeout(timerRef.current);
      setVisible(false);
      timerRef.current = setTimeout(() => setVisible(true), DELAY_MS);
    }

    function onClickCapture(e: MouseEvent) {
      const t = e.target as HTMLElement | null;
      const a = t?.closest?.('a[href]') as HTMLAnchorElement | null;
      if (!a || !shouldTrackAnchorClick(e, a)) return;
      armTimer();
    }

    function onPopState() {
      armTimer();
    }

    document.addEventListener('click', onClickCapture, true);
    window.addEventListener('popstate', onPopState);
    return () => {
      document.removeEventListener('click', onClickCapture, true);
      window.removeEventListener('popstate', onPopState);
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, []);

  if (!visible) return null;

  return (
    <div
      className="fixed inset-0 z-[200] flex items-center justify-center bg-background/90 backdrop-blur-[2px]"
      role="status"
      aria-live="polite"
      aria-busy="true"
    >
      <span className="sr-only">{t('ariaStatus')}</span>
      <div
        className="animate-spin shadow-sm"
        style={{ animationDuration: '1.25s' }}
        aria-hidden
      >
        <Logo size="xl" />
      </div>
    </div>
  );
}

